const PLATFORM_GUIDE_TR: Section[] = [
 {
 icon: Rocket, title: 'Hızlı Başlangıç (Quick Start)',
 items: [
 { q: 'ActLedger nedir ve ne işe yarar?', a: 'ActLedger, işletmenizin tüm operasyonel süreçlerini tek bir platformda yönetmenizi sağlayan kapsamlı bir operasyon yönetim sistemidir. Görev takibi, saha raporları, KPI ölçümü, stok yönetimi, IoT entegrasyonu, canlı harita, iş akışları ve yapay zeka destekli analiz gibi onlarca modülü bir arada sunar.\n\nPlatforma ilk giriş yaptığınızda, yöneticiniz tarafından size atanan rol ve departmana göre erişim yetkiniz belirlenir. Sol taraftaki ana menüden tüm modüllere ulaşabilirsiniz. Üst barda bildirimler, mesajlar ve profil ayarlarına hızlı erişim butonları bulunur.\n\nBaşlamak için aşağıdaki adımları izleyin:\n1. Sol menüden "Kokpit" e tıklayarak dashboard ekranını inceleyin\n2. "Görevler" bölümüne giderek size atanmış görevleri kontrol edin\n3. Profil sayfanızdan bildirim tercihlerinizi ayarlayın\n4. OperIQ asistanına herhangi bir sorunuzu sormak için sağ alttaki sohbet balonuna tıklayın' },
 { q: 'İlk giriş ve şifre belirleme', a: 'Platformu kullanmaya başlamak için yöneticinizin size verdiği e-posta adresi ve geçici şifre ile giriş yapın. Giriş ekranında "E-posta" ve "Şifre" alanlarını doldurun, ardından "Giriş Yap" butonuna basın.\n\nİlk girişte sistem sizden şifrenizi değiştirmenizi isteyecektir. Yeni şifreniz en az 8 karakter uzunluğunda olmalı ve büyük harf, küçük harf, rakam ve özel karakter içermelidir. Şifrenizi belirledikten sonra tekrar giriş yaparak platforma erişebilirsiniz.\n\nŞifrenizi unuttuysanız yöneticinizden (Key Account Manager) yeni şifre talep edin. Platform üzerinde şifre sıfırlama sadece yönetici tarafından yapılabilir.' },
 { q: 'Sol menü ve navigasyon yapısı', a: 'Platformun sol tarafında ana navigasyon menüsü bulunur. Bu menü üzerinden tüm modüllere erişebilirsiniz. Menüdeki ana başlıklar şunlardır:\n\n- Kokpit: Ana dashboard ve özet görünümler\n- Görevler: Görev oluşturma, takip ve yönetim\n- Raporlar: Saha raporları ve analizler\n- KPI Panel: Performans göstergeleri ve hedefler\n- Kullanıcılar: Personel ve departman yönetimi\n- Canlı Harita: Konum takibi ve tesis haritaları\n- IoT Cihazlar: Sensör ve cihaz izleme\n- Stok: Envanter ve malzeme yönetimi\n- Dosyalar: Doküman ve dosya paylaşımı\n- Otomasyon: İş akışları ve otomatik kurallar\n- Mesajlar: Dahili iletişim sistemi\n\nMenüyü daraltmak için sol üstteki hamburger ikonuna tıklayabilirsiniz. Bu sayede çalışma alanınız genişler. Tekrar tıklayarak menüyü açabilirsiniz.' },
 { q: 'OperIQ yapay zeka asistanı nedir?', a: 'OperIQ, ActLedger platformunun içine entegre edilmiş yapay zeka motorudur. Platformda üç farklı OperIQ modülü bulunur:\n\n1. OperIQ Anlık Analiz (sol menüden "İç Görüler"): Şirketinizin operasyonel verilerini analiz eder. Genel özet, verimlilik analizi, risk değerlendirmesi, görev önceliklendirme, departman performansı ve anormallik tespiti yapabilir.\n\n2. OperIQ Asistan (sol menüden "OperIQ"): Doğal dilde soru sorabileceğiniz sohbet arayüzüdür. Görevler, raporlar, KPI ve stok hakkında sorular sorabilirsiniz. Fotoğraf analizi de yapabilir.\n\n3. Görsel Oluşturma (Dashboard içerisinde): Doğal dil ile tarif ettiğiniz grafik ve görselleştirmeleri otomatik oluşturur.\n\nOperIQ, şirketinize özel verileri kullanarak bağlama uygun sonuçlar üretir. Türkçe veya İngilizce kullanabilirsiniz.' },
 { q: 'Dil ve tema ayarları', a: 'ActLedger Türkçe ve İngilizce dillerini destekler. Dili değiştirmek için sağ üst köşedeki profil ikonunuza tıklayın ve dil seçeneklerinden istediğinizi seçin. Dil değişikliği anında uygulanır ve sayfa yenilenmesine gerek kalmaz.\n\nPlatform açık (light) tema ile çalışır. Tüm sayfalar tutarlı ve okunabilir bir tasarımla sunulur. Tarayıcınızın yakınlaştırma (zoom) özelliğini kullanarak metin boyutunu ihtiyacınıza göre ayarlayabilirsiniz (Ctrl + veya Ctrl - kısayolları ile).' },
 ],
 },
 {
 icon: Monitor, title: 'Kokpit & Dashboard', path: '/panel',
 items: [
 { q: 'Dashboard nasıl kullanılır?', a: 'Sol menüden "Kokpit" e tıklayarak ana dashboard ekranına ulaşın. Dashboard, işletmenizin genel durumunu tek bakışta görmenizi sağlayan özet ekranıdır. Burada görev istatistikleri, KPI özeti, son raporlar, bildirimler ve departman bazında performans göstergeleri yer alır.\n\nSürüklenebilir widgetlar ile kendi görünümünüzü oluşturabilirsiniz. Her widget bir veri kaynağını görselleştirir - pasta grafik, çubuk grafik, sayı kartı, liste veya harita şeklinde olabilir. Sağ üstteki "+" butonu ile yeni widget ekleyebilir, widgetları sürükleyerek sıralayabilirsiniz.\n\nDashboard verileri varsayılan olarak canlı güncellenir. Sağ üstteki yenileme butonuyla verileri manuel olarak da güncelleyebilirsiniz. Tarih aralığını değiştirerek farklı zaman dilimlerindeki verileri görebilirsiniz.' },
 { q: 'Yeni dashboard nasıl eklenir?', a: 'Dashboard başlığının yanındaki dropdown\'dan "Yeni Dashboard" seçin. Aşağıdaki adımları izleyin:\n\n1. Dashboard\'a bir ad verin (ör: "Haftalık Üretim Özeti" veya "Saha Performansı")\n2. Widget ekle butonuna tıklayın ve istediğiniz widget tipini seçin\n3. Her widget için veri kaynağı, görselleştirme tipi ve filtreleri ayarlayın\n4. Widgetları sürükleyerek istediğiniz düzenle yerleştirin\n5. "Kaydet" butonuna basarak dashboard\'unuzu kaydedin\n\nBirden fazla dashboard oluşturabilir ve aralarında hızlıca geçiş yapabilirsiniz. Örneğin bir dashboard günlük operasyonlar için, başkası haftalık yönetim toplantıları için olabilir. Dashboard\'ları diğer kullanıcılarla da paylaşabilirsiniz.' },
 { q: 'OperIQ ile grafik nasıl oluşturulur?', a: '"Veri Görselleştirme" butonuna tıklayın. Açılan pencerede doğal dilde ne görmek istediğinizi yazın. OperIQ otomatik olarak en uygun grafik tipini seçer ve yapılandırır.\n\nÖrnek komutlar:\n- "Departmanlara göre görev dağılımı" - pasta grafik oluşturur\n- "Son 30 gündeki rapor sayısı" - çizgi grafik oluşturur\n- "En yüksek KPI performansına sahip 10 departman" - çubuk grafik oluşturur\n- "Stok seviyesi kritik olan ürünler" - tablo görüntüsünde listeler\n\nOluşturulan grafiği dashboard\'unuza widget olarak ekleyebilir, PNG veya PDF formatında indirebilir ya da doğrudan rapor içerisinde kullanabilirsiniz. OperIQ ayrıca veriler hakkında otomatik yorum ve öneriler de sunar.' },
 { q: 'Widget tipleri ve özellikleri', a: 'Dashboard\'da kullanabileceğiniz widget tipleri şunlardır:\n\n- Sayı Kartı: Tek bir metrik değerini büyük rakamlarla gösterir (ör: toplam açık görev sayısı, bugünün rapor sayısı)\n- Pasta Grafik: Dağılım verilerini oransal olarak gösterir (ör: görev durumlarına göre dağılım)\n- Çubuk Grafik: Karşılaştırmalı verileri yan yana gösterir (ör: departman bazında performans)\n- Çizgi Grafik: Zaman içerisindeki değişimi izler (ör: haftalık görev tamamlanma trendi)\n- Tablo: Detaylı veri listesini satırlar halinde gösterir (ör: geciken görevler listesi)\n- Harita: Konum bazlı verileri harita üzerinde gösterir (ör: saha ekiplerinin konumları)\n\nHer widget üzerinde fareyi gezdirdiğinizde sağ üst köşede düzenle, boyutlandır ve sil butonları görünür. Widget ayarlarından veri kaynağını, renkleri ve yenileme sıklığını değiştirebilirsiniz.' },
 { q: 'Dashboard filtreleme ve tarih aralığı', a: 'Dashboard\'un üst kısmındaki filtre çubuğunu kullanarak görünen verileri daraltabilirsiniz. Kullanabileceğiniz filtreler:\n\n- Tarih Aralığı: Bugün, bu hafta, bu ay, son 30 gün veya özel tarih aralığı seçebilirsiniz\n- Departman: Belirli bir departmanın verilerini görmek için seçim yapın\n- Kullanıcı: Belirli bir kullanıcıya ait verileri filtrelemek için seçin\n- Durum: Görev veya rapor durumuna göre filtreleyin\n\nFiltreler tüm widgetlara aynı anda uygulanır. Filtreleri temizlemek için "Filtreleri Sıfırla" butonuna basın. Sık kullandığınız filtre kombinasyonlarını kayıtlı görünüm olarak saklayabilirsiniz.' },
 ],
 },
 {
 icon: ClipboardList, title: 'Görev Yönetimi', path: '/gorevler',
 items: [
 { q: 'Yeni görev nasıl oluşturulur?', a: 'Sol menüden "Görevler"e gidin, sağ üstteki "Yeni Görev" butonuna basın. Görev oluşturma formu açılacaktır. Aşağıdaki adımları izleyin:\n\n1. Başlık: Görevi kısa ve net bir şekilde tanımlayan bir başlık girin\n2. Açıklama: Görevin detaylarını, beklenen çıktıları ve önemli notları yazın\n3. Departman: Görevin ait olduğu departmanı seçin\n4. Atanan Kişi: Görevi yapacak personeli seçin (birden fazla kişi atayabilirsiniz)\n5. Öncelik: Düşük, Normal, Yüksek veya Kritik öncelik seviyesini belirleyin\n6. Teslim Tarihi: Görevin tamamlanması gereken son tarihi seçin\n7. Etiketler: Görevi kategorize etmek için etiketler ekleyin\n\nGörev oluşturduktan sonra atanan kişiye otomatik bildirim gönderilir. Görev kartında tüm detaylar görünür ve ilerleme durumu takip edilebilir.' },
 { q: 'Görev durumu nasıl güncellenir?', a: 'Görev kartına tıklayarak detay penceresini açın. Durum alanı sağ üstte yer alır ve şu seçenekleri içerir:\n\n- Beklemede: Görev henüz başlanmamış, atanmış durumda\n- Devam Ediyor: Görev üzerinde aktif olarak çalışılıyor\n- İncelemede: Görev tamamlanmış ve yöneticinin onayını bekliyor\n- Tamamlandı: Görev başarıyla tamamlanmış\n- İptal Edildi: Görev iptal edilmiş\n\nDurum değişikliği yapıldığında sistem otomatik olarak zaman damgası kaydeder ve ilgili kişilere bildirim gönderir. Görev geçmişinde tüm durum değişiklikleri tarih ve saat bilgisiyle birlikte görüntülenir.\n\nGörev üzerinde yorum da bırakabilirsiniz. Yorum alanına yazın ve "Gönder" butonuna basın. Yorumlar tüm ilgili kişilere bildirim olarak iletilir.' },
 { q: 'Checklist nasıl eklenir?', a: 'Görev detayında "Checklist" bölümüne gidin ve yeni maddeler ekleyin. Checklist, bir görevi alt adımlara bölmenize olanak tanır ve ilerlemenin görsel olarak takip edilmesini sağlar.\n\nChecklist kullanmak için:\n1. Görev detay sayfasını açın\n2. "Checklist" bölümünde "Yeni Madde Ekle" butonuna basın\n3. Madde metnini yazın ve Enter\'a basın\n4. Birden fazla madde ekleyerek görev adımlarını tanımlayın\n5. Her tamamlanan adımı işaretleyin - ilerleme çubuğu otomatik güncellenir\n\nChecklist ilerlemesi yüzde olarak görev kartında da görünür. Örneğin 8 maddeden 4\'ü tamamlanmışsa "%50" şeklinde gösterilir. Bu sayede görevlerin ne aşamada olduğunu listeden bile görebilirsiniz.' },
 { q: 'Görev filtreleme ve arama', a: 'Görev listesinin üstündeki filtre çubuğu ile görevleri çeşitli kriterlere göre filtreleyebilirsiniz:\n\n- Durum Filtresi: Beklemede, Devam Ediyor, Tamamlandı gibi durumlara göre filtreleyin\n- Öncelik Filtresi: Kritik, Yüksek, Normal, Düşük önceliklere göre sıralayın\n- Departman Filtresi: Belirli departmanlara ait görevleri görün\n- Tarih Filtresi: Belirli tarih aralığındaki görevleri listeleyin\n- Atanan Kişi: Belirli bir kişiye atanmış görevleri bulun\n\nArama çubuğuna görev başlığı veya açıklamasındaki anahtar kelimeleri yazarak hızlı arama yapabilirsiniz. Filtreler birlikte kullanılabilir - örneğin "Kritik öncelikli ve geciken görevler" gibi kombinasyonlar oluşturabilirsiniz.' },
 { q: 'Görev takvimi ve zaman çizelgesi', a: 'Görev listesinin üst kısmındaki görünüm seçeneklerinden "Takvim" görünümüne geçebilirsiniz. Takvim görünümünde görevler teslim tarihlerine göre takvim üzerinde gösterilir.\n\nFarklı görünüm seçenekleri şunlardır:\n- Liste Görünümü: Görevleri satırlar halinde listeler, en çok detay bu görünümde görülür\n- Kanban Görünümü: Görevleri durum sütunlarında kartlar halinde gösterir, sürükle-bırak ile durum değiştirebilirsiniz\n- Takvim Görünümü: Görevleri takvim üzerinde tarihlere göre yerleştirir\n\nKanban görünümünde görev kartını bir sütundan diğerine sürükleyerek durum değişikliği yapabilirsiniz. Örneğin "Beklemede" sütunundan "Devam Ediyor" sütununa sürüklemek görevin durumunu otomatik günceller.' },
 { q: 'Görev yanıt sistemi nasıl çalışır?', a: 'Görevlere atanan kişiler görev üzerinden doğrudan yanıt verebilir. Yanıt sistemi ile görevin ilerleyişi hakkında bilgi paylaşabilir, soru sorabilir veya sorun bildirebilirsiniz.\n\nYanıt vermek için:\n1. Görev detay sayfasını açın\n2. Alt kısımda yer alan "Yanıt / Yorum" bölümüne gidin\n3. Mesajınızı yazın, gerekirse dosya veya fotoğraf ekleyin\n4. "Gönder" butonuna basın\n\nYanıtlar kronolojik sıraya ile listelenir ve tüm ilgili kişilere bildirim gönderilir. Yönetici, görev üzerindeki yanıtları inceleyerek gerekirse talimat verebilir veya görevi yeniden atayabilir. Bu sistem, görev hakkındaki tüm iletişimi tek bir yerde toplayarak bilgi kayıplarını önler.' },
 ],
 },
 {
 icon: ClipboardList, title: 'İş Siparişleri', path: '/is-siparisleri',
 items: [
 { q: 'İş Siparişi nedir?', a: 'İş Siparişi, departmanlar arası veya departman içi birimler arası resmi iş talep ve takip sistemidir. Mevcut görev sisteminden farklı olarak iki katmanlı onay mekanizması ve iki taraflı kapanma süreci içerir.\n\nİş Siparişi ile:\n- Bir departman başka bir departmana resmi iş talebi gönderebilir\n- Departman içinde süpervizörler birbirlerine iş siparişi açabilir\n- Talep eden tarafın müdürü siparişi önce onaylar, ardından hedef departmana iletilir\n- Hedef departman kabul eder, işi yapar ve tamamlandığında talep eden tarafa geri bildirir\n- Talep eden müdür sonucu onaylayarak siparişi kapatır\n\nHer sipariş otomatik olarak WO-2026-0001 formatında benzersiz bir kod alır. Tüm durum değişiklikleri, yorumlar ve ekler kronolojik olarak kaydedilir.' },
 { q: 'İş Siparişi nasıl oluşturulur?', a: 'Sol menüden "İş Siparişleri" sayfasına gidin ve sağ üstteki "Yeni İş Siparişi" butonuna basın. Formu doldurun:\n\n1. Başlık: Siparişi kısa ve net tanımlayan bir başlık girin\n2. Açıklama: İşin detaylarını, beklentilerinizi ve önemli notları yazın\n3. Hedef Departman: İşi yapacak departmanı seçin\n4. Talep Eden Departman: Varsayılan olarak kendi departmanınız seçilidir\n5. Öncelik: Düşük, Normal, Yüksek veya Kritik seçin\n6. Son Tarih: İşin tamamlanması gereken son tarihi belirleyin\n7. Tahmini Süre: Beklenen çalışma süresini saat cinsinden girin\n8. Tahmini Maliyet: Varsa beklenen maliyeti girin\n9. İş Kalemleri: Alt adımlar ekleyerek yapılacak işleri listeleyin\n\n"Taslak Kaydet" ile taslak olarak saklayabilir veya "Gönder" ile doğrudan müdür onayına gönderebilirsiniz.\n\nNot: İş siparişi açabilmek için Süpervizör veya üstü rol seviyesine sahip olmanız gerekir.' },
 { q: 'İş Siparişi durum akışı nasıl çalışır?', a: 'Her iş siparişi 7 aşamalı bir süreçten geçer:\n\n1. Taslak: Sipariş oluşturuldu ama henüz gönderilmedi. Düzenleme yapılabilir.\n2. Müdür Onayı Bekliyor: Gönderildi, talep eden departmanın müdürü inceliyor. Müdür onaylayabilir, reddedebilir veya revize isteyebilir.\n3. Karşı Taraf Bekliyor: Müdür onayladı, hedef departmana iletildi. Hedef departman müdürü veya süpervizörü kabul veya ret yapabilir.\n4. Devam Ediyor: Karşı taraf kabul etti, iş yapılıyor.\n5. Tamamlandı Onayı Bekliyor: Karşı departman müdürü "biz bitirdik" dedi, kendi müdürünün onayını bekliyor.\n6. Açan Onayı Bekliyor: Hedef departman tamamladı, talep eden departman müdürü sonucu inceliyor.\n7. Kapandı: Talep eden müdür sonucu onayladı, sipariş başarıyla kapandı.\n\nHer aşamada red veya revize isteği yapılabilir. Reddedilen siparisler "Reddedildi" durumuna düşer. Revize istenen siparisler düzeltilip tekrar gönderilebilir.' },
 { q: 'Onay ve kabul süreci nasıl işler?', a: 'İş siparişinde iki katmanlı onay mekanizması vardır:\n\nİlk Katman - Talep Eden Departman Müdürü:\n- Sipariş gönderildiğinde talep eden departmanın müdürüne bildirim gider\n- Müdür siparişi inceler ve üç seçenekten birini yapar:\n  - Onayla: Sipariş hedef departmana iletilir\n  - Reddet: Sipariş iptal edilir, sebep belirtmek zorunludur\n  - Revize İste: Sipariş açan kişiye geri döner, düzeltme yapması istenir\n\nİkinci Katman - Hedef Departman:\n- Hedef departmanın müdürü veya süpervizörü siparişi inceler\n- Kabul Et: İş başlar, durumu "Devam Ediyor" olur\n- Reddet: Sipariş reddedilir, sebep belirtilir\n\nKapanma süreci de iki taraflıdır: hedef departman müdürü "tamamlandı" der, ardından talep eden müdür sonucu onaylar ve sipariş kapanır. Talep eden müdür sonucu beğenmezse "Revize İste" ile işi geri gönderebilir.' },
 { q: 'Maliyet ve malzeme takibi nasıl yapılır?', a: 'Her iş siparişinde maliyet ve malzeme takibi yapılabilir:\n\nMaliyet Takibi:\n- Sipariş oluşturulurken "Tahmini Maliyet" girilir\n- İş tamamlandığında "Gerçekleşen Maliyet" girilir\n- Para birimi varsayılan olarak TRY dir, değiştirilebilir\n- Tahmini ve gerçekleşen maliyet karşılaştırması detay sayfasında görülür\n\nSüre Takibi:\n- "Tahmini Süre" saat cinsinden girilir\n- Tamamlandığında "Gerçekleşen Süre" girilir\n- Sapma analizi yapılabilir\n\nMalzeme Takibi:\n- Detay sayfasındaki "Malzemeler" sekmesinden kullanılan malzemeleri ekleyin\n- Her malzeme için: ad, miktar, birim (adet, kg, metre vb.) ve birim maliyet girin\n- Stok sistemiyle opsiyonel bağlantı kurulabilir\n- Malzeme listesi iş siparişinin toplam maliyet hesabında kullanılabilir' },
 { q: 'İş Kalemleri (Checklist) nasıl kullanılır?', a: 'İş kalemleri, bir siparişi alt adımlara bölmenize olanak tanır:\n\nKalem Ekleme:\n- Sipariş oluşturulurken "İş Kalemleri" bölümünden alt adımlar ekleyin\n- Her kalem için bir başlık girin\n- Kalemleri sürükleyerek sıralayabilirsiniz\n\nKalem Takibi:\n- Hedef departman çalışanları her kalemi tamamlandıkça işaretler\n- Tamamlanan kalemler tarih ve kim tarafından tamamlandığı bilgisiyle kaydedilir\n- İlerleme yüzdesi otomatik hesaplanır\n\nBu özellik özellikle çok adımlı işlerde (bakım, kurulum, denetim vb.) faydalıdır. Her adımın kim tarafından ne zaman tamamlandığı kayıt altına alınır.' },
 { q: 'Yorum ve dosya ekleme nasıl yapılır?', a: 'İş siparişlerine iki aşamada dosya ve yorum eklenebilir:\n\nYorumlar:\n- Detay sayfasındaki "Yorumlar" sekmesine gidin\n- Mesajınızı yazın ve "Gönder" butonuna basın\n- Yorumlar kronolojik olarak listelenir\n- Karşı tarafa bildirim gider (bildirim tercihi açıksa)\n\nDosya Ekleri:\n- "Ekler" sekmesinden dosya yükleyin\n- Sipariş açılırken eklenen dosyalar "Talep" etiketiyle görünür\n- İş tamamlanırken eklenen dosyalar "Tamamlama" etiketiyle görünür\n- Maksimum dosya boyutu: 10 MB\n\nDosya ve yorumlar, siparişin tüm geçmişini tek bir yerde toplayarak iletişim kayıplarını önler.' },
 { q: 'İş Siparişi geçmişi ve zaman çizelgesi', a: 'Her iş siparişinin detay sayfasında "Geçmiş" sekmesi bulunur. Bu sekme, siparişin oluşturulmasından kapanmasına kadar tüm olayları kronolojik olarak gösterir:\n\n- Sipariş oluşturuldu (kim, ne zaman)\n- Müdür onayına gönderildi\n- Müdür onayladı / reddetti / revize istedi\n- Karşı taraf kabul etti / reddetti\n- İş tamamlandı\n- Sipariş kapandı\n- Her adımda eklenen notlar\n\nBu geçmiş, denetim ve sorumluluk takibi için önemlidir. Kim ne zaman ne yaptı sorusunun yanıtı her zaman buradadır.' },
 { q: 'Bildirim tercihleri nasıl ayarlanır?', a: 'İş siparişi bildirimlerini "Ayarlar" sayfasından kişiselleştirebilirsiniz. Açıp kapatabileceğiniz bildirim tipleri:\n\nVarsayılan açık:\n- Yeni iş siparişi geldiğinde\n- Sipariş onaylandığında veya reddedildiğinde\n- Sipariş kabul edildiğinde\n- İş tamamlandığında\n- Gecikme durumunda (son tarih aşıldığında)\n\nVarsayılan kapalı:\n- Yorum eklendiğinde\n- Dosya yüklendiğinde\n\nBildirimler hem platform içi (zil ikonu) hem de push bildirim (mobil) olarak gönderilir.' },
 { q: 'Mobil uygulamada İş Siparişleri nasıl kullanılır?', a: 'Mobil uygulamada (App Store, Play Store veya PWA) İş Siparişleri modülüne alt menüden erişebilirsiniz:\n\nListe Görünümü:\n- Kart bazlı liste, durum ve öncelik renkleriyle\n- Üst barda hızlı filtre sekmeleri (Tümü, Taslak, Onay Bekliyor, Devam Ediyor, Kapandı)\n- Sağ üstte "Yeni" butonu ile sipariş oluşturma\n\nDetay Görünümü:\n- Karta dokunarak detay ekranını açın\n- Bilgi kartı, iş kalemleri, yorumlar, ekler, malzemeler ve geçmiş sekmeleri\n- Altta sabit aksiyon butonları (duruma göre değişir)\n\nSipariş Oluşturma:\n- Başlık, açıklama, hedef departman, öncelik, son tarih bilgilerini girin\n- "Taslak Kaydet" veya doğrudan "Gönder" seçenekleri\n\nTüm bildirimler push bildirim olarak mobil cihaza gelir. Bildirime dokunarak doğrudan ilgili siparişe gidebilirsiniz.' },
 ],
 },
 {
 icon: FileText, title: 'Saha Raporları', path: '/raporlar',
 items: [
 { q: 'Rapor nasıl oluşturulur?', a: 'Sol menüden "Raporlar"a gidin ve "Yeni Rapor Oluştur" butonuna basın. Form alanlarını doldurun:\n\n1. Başlık: Rapor konusunu özetleyen net bir başlık girin\n2. Açıklama: Durumu detaylı bir şekilde anlatın\n3. Departman: Raporun ilgili olduğu departmanı seçin\n4. Öncelik: Düşük, Orta, Yüksek veya Kritik olarak belirleyin\n5. Etiketler: Kategorilendirme için etiketler ekleyin (virgül ile ayırın)\n\nRapor "Taslak" olarak kaydedilir. Taslak raporu canlı almak için rapor kartına tıklayın ve "Gönder" butonuna basın.' },
 { q: 'Rapor durumlarını yönetme ve canlı alma', a: 'Her raporun bir yaşam döngüsü vardır:\n\n- Taslak: Rapor oluşturuldu ama henüz gönderilmedi. "Gönder" ile canlı alın veya "İlet" ile doğrudan personele gönderin.\n- Gönderildi/İnceleniyor: Rapor inceleme sürecinde. "Onayla" veya "Reddet" ile işlem yapın. "İlet" butonu ile alt birimlere yönlendirin.\n- Onaylandı: Rapor tamamlanmış ve onaylanmış.\n- Reddedildi: Rapor reddedilmiş.\n\nHer durum değişikliğinde rapor sahibine otomatik bildirim gönderilir.' },
 { q: 'Raporu hiyerarşik olarak iletme', a: 'Raporları hiyerarşik yapıya göre alt birimlere iletebilirsiniz:\n\n1. Rapor detayında "İlet" butonuna basın\n2. Kullanıcı seçim ekranı açılır - Mobil Kullanıcılar ve Platform Kullanıcıları ayrı gruplar halinde listelenir\n3. "Hepsini Seç" ile tüm kullanıcıları seçebilir veya tek tek işaretleyebilirsiniz\n4. "İlet" butonuna basarak raporu gönderin\n\nHiyerarşik iş akışı:\n- Genel Müdür: Tüm departmanlara iletir\n- Departman Müdürü: Süpervizör ve alt birimlere iletir\n- Süpervizör: Saha personeline (işçi, teknisyen) iletir\n\nİletilen raporlar mobil saha kullanıcısının "Formlar" sekmesinde "Rapor: ..." başlığıyla görünür. Saha personeli raporu açar, işlem yapar (Tamamlandı/Sorun Var) ve not ekler. İşlem tamamlandığında platformdaki ilgili kullanıcılara anlık bildirim gider ve OperIQ otomatik analiz başlatır.' },
 { q: 'OperIQ rapor analizi nasıl çalışır?', a: 'Rapor oluşturulduğunda ve saha personeli işlem yaptığında OperIQ otomatik olarak analiz eder:\n\n- Metin Analizi: Rapor ve saha notlarını inceleyerek anahtar bulguları çıkarır\n- Risk Değerlendirmesi: Potansiyel etkiyi ve aciliyet seviyesini değerlendirir\n- Önerilen Aksiyonlar: Yapılması gereken eylemleri listeler\n- Olası Nedenler: Muhtemel sebepleri analiz eder\n\nAnaliz sonuçları rapor detay sayfasında "OperIQ Analizi" bölümünde görüntülenir. Analiz butonuna basarak manuel analiz de başlatabilirsiniz.' },
 { q: 'Rapor filtreleme ve geçmiş arama', a: 'Rapor listesini filtrelemek için üst kısımdaki filtre araçlarını kullanabilirsiniz:\n\n- Tarih Aralığı: Belirli bir zaman dilimindeki raporları görün\n- Departman: Belirli departmanlara ait raporları listeleyin\n- Şiddet Derecesi: Kritik, yüksek, orta veya düşük şiddet filtresi\n- Durum: Oluşturuldu, inceleniyor, çözüldü gibi durumlara göre filtreleyin\n- Arama: Rapor başlığı veya içeriği içerisinde anahtar kelime arayın\n\nRaporları Excel formatında dışa aktarabilirsiniz. Bu sayede detaylı analiz veya yönetim sunumu için rapor verilerini kullanabilirsiniz.' },
 { q: 'Raporlara dosya ve fotoğraf ekleme', a: 'Rapor oluşturma veya düzenleme ekranında dosya ve fotoğraf ekleme bölümü bulunur.\n\nFotoğraf eklemek için:\n- "Fotoğraf Ekle" butonuna basın\n- Bilgisayarınızdan dosya seçin veya sürükleyip bırakın\n- Birden fazla fotoğraf ekleyebilirsiniz\n- Desteklenen formatlar: JPG, PNG, GIF, WebP\n- Maksimum dosya boyutu: 10 MB\n\nDosya eklemek için:\n- "Dosya Ekle" butonuna basın\n- PDF, Word, Excel veya metin dosyası seçin\n- Dosyalar rapor detayında görüntülenir ve indirilebilir\n\nYüklenen fotoğraflar rapor detayında galeri görünümünde görüntülenir. Fotoğraflara tıklayarak büyütebilir ve aralarında gezinebilirsiniz.' },
 ],
 },
 {
 icon: BarChart3, title: 'KPI Yönetimi', path: '/kpi-panel',
 items: [
 { q: 'KPI nasıl tanımlanır?', a: 'Sol menüden "KPI Panel"e gidin. Sektör şablonundan hazır KPI\'lar zaten yüklenmiştir. Yeni KPI eklemek veya mevcut KPI\'ları düzenlemek için aşağıdaki adımları izleyin:\n\n1. "KPI Ekle" butonuna basın\n2. KPI adını ve açıklamasını girin\n3. Ölçüm birimini seçin (yüzde, sayı, süre, tutar vb.)\n4. Hedef değerini belirleyin\n5. Ölçüm sıklığını seçin (günlük, haftalık, aylık, çeyreklik)\n6. İlgili departmanı atayın\n7. KPI katmanını seçin (stratejik, taktik, operasyonel, bireysel veya AI)\n\nKPI tanımlandıktan sonra ilgili departman ve kullanıcılar bu KPI değerini düzenli olarak girebilir. Gerçekleşen değerler hedefe kıyasla otomatik olarak performans yüzdesi hesaplanır.' },
 { q: 'KPI katmanları nedir?', a: 'ActLedger 5 katmanlı KPI yapısı sunar. Her katman farklı yönetim seviyesine hitap eder:\n\n1. Stratejik KPI\'lar (Üst Yönetim): Şirketin genel performansını ölçer. Örnek: yıllık gelir büyümesi, müşteri memnuniyeti endeksi, pazar payı\n2. Taktik KPI\'lar (Orta Yönetim): Departman hedeflerini ölçer. Örnek: departman bazında verimlilik, proje tamamlanma oranı\n3. Operasyonel KPI\'lar (Saha): Günlük operasyonların etkinliğini ölçer. Örnek: günlük üretim miktarı, arıza çözüm süresi\n4. Bireysel KPI\'lar (Kişisel): Her çalışanın bireysel performansını ölçer. Örnek: görev tamamlama oranı, cevap süresi\n5. AI KPI\'lar (OperIQ Üretimi): OperIQ tarafından verilerden otomatik türetilen metrikler. Örnek: trend analizi, anomali tespiti, tahminleme skorları\n\nKPI panelinde katman bazında filtreleme yaparak sadece ilgilendiğiniz seviyedeki KPI\'ları görebilirsiniz.' },
 { q: 'KPI gerçekleşen değer girişi nasıl yapılır?', a: 'KPI değer girişi için iki yöntem mevcuttur:\n\nManuel Giriş:\n1. KPI Panel sayfasında ilgili KPI\'yı bulun\n2. "Değer Gir" butonuna tıklayın\n3. Gerçekleşen değeri girin ve tarih bilgisini seçin\n4. Gerekirse not veya açıklama ekleyin\n5. "Kaydet" butonuna basın\n\nToplu Giriş (Excel):\n1. KPI Panel sayfasında "Toplu Giriş" butonuna basın\n2. Şablon Excel dosyasını indirin\n3. Değerleri Excel\'de doldurun\n4. Dosyayı yükleyin ve önizlemede kontrol edin\n5. "Kaydet" ile tüm değerleri kaydedin\n\nDüzenli veri girişi yapılmayan KPI\'lar için sistem uyarı oluşturur ve ilgili departman yöneticisine hatırlatma gönderir.' },
 { q: 'KPI performans görüntüleme ve raporlama', a: 'KPI panelinde her KPI için görsel performans göstergeleri bulunur:\n\n- Yeşilden kırmızıya renk skalası hedefe yakınlığı gösterir\n- Trend okları yükseliş veya düşüş yönünü belirtir\n- Grafik görünümde zaman içerisindeki değişim izlenebilir\n\nDetaylı KPI raporları için:\n- KPI adına tıklayarak detay sayfasını açın\n- Geçmiş verileri grafik üzerinde inceleyin\n- Departman veya kişi bazında karşılaştırma yapın\n- OperIQ analizi ile trend tahminlerini görün\n\nKPI verilerini PDF veya Excel formatında dışarı aktarabilirsiniz. Aylık KPI özet raporları otomatik olarak oluşturulur ve yönetim ekibine gönderilir.' },
 { q: 'Sektör şablonları ve hazır KPI setleri', a: 'ActLedger, 15 farklı sektör için hazır KPI şablonları sunar. Şirketiniz oluşturulurken sektörünüze uygun şablon otomatik olarak yüklenir. Bu şablonlar binlerce KPI içeren kapsamlı kütüphanelerdir.\n\nHer sektör şablonunda:\n- Departman bazında gruplanmış KPI\'lar\n- Ölçüm birimleri ve hedef aralıkları ön-tanımlı olarak gelir\n- Sektöre özgü metrikler ve terminoloji kullanılır\n\nŞablon KPI\'larını ihtiyaçlarınıza göre düzenleyebilirsiniz: hedef değerlerini değiştirin, gereksiz KPI\'ları devre dışı bırakın veya yenilerini ekleyin. Şablona ek olarak kendi özel KPI\'larınızı da tanımlayabilirsiniz.' },
 ],
 },
 {
 icon: Users, title: 'Kullanıcı & Departman Yönetimi', path: '/kullanicilar',
 items: [
 { q: 'Yeni kullanıcı nasıl eklenir?', a: '"Kullanıcılar" sayfasından "Yeni Kullanıcı" butonuna basın. Kullanıcı oluşturma formunu doldurun:\n\n1. Ad ve Soyad: Kullanıcının tam adını girin\n2. E-posta: Giriş için kullanılacak e-posta adresini girin\n3. Telefon: İletişim için telefon numarasını girin\n4. Rol: 8 rol seviyesinden birini seçin (aşağıda detaylı açıklama var)\n5. Departman: Kullanıcının bağlı olduğu departmanı seçin\n6. Giriş Kodu: Sistem otomatik olarak ACT-XXXXXX formatında bir giriş kodu üretir\n\nKullanıcı oluşturulunca geçici şifre ile birlikte giriş bilgileri e-posta ile iletilir. Kullanıcı ilk girişinde şifresini değiştirmek zorundadır. Toplu kullanıcı eklemek için Excel şablonunu kullanabilirsiniz.' },
 { q: 'Rol seviyeleri nedir?', a: '8 seviyeli yetki sistemi hiyerarşik olarak çalışır. Her seviye bir üst seviyenin tüm yetkilerini içerir:\n\n1. İşçi (Seviye 1): Kendisine atanan görevleri görebilir ve tamamlayabilir, form doldurabilir\n2. Teknisyen (Seviye 2): İşçi yetkilerine ek olarak rapor oluşturabilir ve IoT verilerini görebilir\n3. Usta (Seviye 3): Görev oluşturabilir ve kendi ekibine atayabilir\n4. Süpervizör (Seviye 4): Departmanındaki tüm görev ve raporları görebilir, stok hareketi yapabilir\n5. Şef (Seviye 5): Departman KPI\'larını yönetebilir, iş akışı oluşturabilir\n6. Müdür (Seviye 6): Birden fazla departmanı yönetebilir, kullanıcı ekleyebilir\n7. Direktör (Seviye 7): Tüm departmanları görebilir, otomasyon kuralları oluşturabilir\n8. Genel Müdür (Seviye 8): Tam yetki - tüm modüllere ve ayarlara erişim\n\nRol ataması yapılırken dikkatli olun. Bir kullanıcının rolünü daha sonra değiştirebilirsiniz.' },
 { q: 'Departman nasıl oluşturulur ve yönetilir?', a: 'Departman yönetimi için "Kullanıcılar" sayfasındaki "Departmanlar" sekmesine geçin. Yeni departman oluşturmak için:\n\n1. "Yeni Departman" butonuna basın\n2. Departman adını girin\n3. Üst departmanı seçin (varsa - hiyerarşik yapı için)\n4. Departman yöneticisini atayın\n5. Varsayılan KPI setini seçin\n6. "Kaydet" butonuna basın\n\nDepartman hiyerarşisi ağaç yapısında görüntülenir. Her departmanın altında alt departmanlar oluşturabilirsiniz. Örneğin "Üretim" departmanının altında "Montaj", "Kalite Kontrol", "Paketleme" gibi alt departmanlar tanımlayabilirsiniz.\n\nDepartman yöneticisi değiştirildiğinde tüm atamalar ve yetkiler otomatik olarak güncellenir.' },
 { q: 'Kullanıcı profilini düzenleme', a: 'Bir kullanıcının profilini düzenlemek için kullanıcı listesinde ismine tıklayın. Profil sayfasında şu alanları güncelleyebilirsiniz:\n\n- Kişisel Bilgiler: Ad, soyad, telefon, e-posta\n- Rol ve Departman: Yetki seviyesi ve bağlı departman\n- Profil Fotoğrafı: Kullanıcının fotoğrafı\n- Bildirim Tercihleri: Hangi bildirimleri alacağını ayarlama\n- Şifre Sıfırlama: Kullanıcının şifresini sıfırlayabilirsiniz\n\nKullanıcıları devre dışı bırakabilirsiniz (silmek yerine). Devre dışı bırakılan kullanıcı giriş yapamaz ancak geçmiş kayıtları korunur. Bunu "Hesabı Devre Dışı Bırak" butonu ile yapabilirsiniz.' },
 { q: 'Toplu kullanıcı ekleme (Excel)', a: 'Çok sayıda kullanıcı eklemek için Excel şablon yüklemesini kullanın:\n\n1. "Kullanıcılar" sayfasında "Toplu Ekle" butonuna basın\n2. "Şablon İndir" ile boş Excel şablonunu indirin\n3. Şablondaki sütunları doldurun: Ad, Soyad, E-posta, Telefon, Departman, Rol\n4. Doldurulmuş dosyayı yükleyin\n5. Önizleme ekranında verileri kontrol edin - hatalı satırlar kırmızı ile işaretlenir\n6. "Kullanıcıları Oluştur" butonuyla tüm kullanıcıları tek seferde ekleyin\n\nHer kullanıcıya otomatik giriş kodu ve geçici şifre üretilir. Giriş bilgilerini içeren bir özet dosyası indirebilirsiniz. Bu dosyayı ilgili kişilere güvenli bir şekilde iletin.' },
 ],
 },
 {
 icon: Map, title: 'Canlı Harita', path: '/harita',
 items: [
 { q: 'Personel konumları nasıl görüntülenir?', a: '"Canlı Harita" sayfasında aktif konum paylaşan personelleri harita üzerinde görün. Her personel bir işaretçi (pin) ile gösterilir ve üstüne tıklayınca ad, departman ve son konum güncelleme zamanı görüntülenir.\n\nHarita üzerindeki filtreleme seçenekleri:\n- Departman Filtresi: Belirli departmanlardaki personeli görün\n- Durum Filtresi: Aktif, molada veya çevrimdışı personeli filtreleyin\n- Zaman Filtresi: Son 1 saat, 4 saat veya 24 saat içerisindeki konumları görün\n\nPersonel konumları varsayılan olarak 60 saniyede bir güncellenir. Harita üzerinde yakınlaştırıp uzaklaştırarak farklı detay seviyelerinde görebilirsiniz. Belirli bir bölgeye odaklanmak için haritayı sürükleyin veya arama çubuğundan adres arayın.' },
 { q: 'Tesis nasıl işaretlenir?', a: 'Harita üzerinde tesis, fabrika, depo veya ofis konumlarını işaretleyebilirsiniz:\n\n1. Harita üzerinde istediğiniz konuma sağ tıklayın\n2. "Yeni Tesis Ekle" seçeneğini seçin\n3. Tesis adını ve tipini girin (Fabrika, Ofis, Depo, Şantiye vb.)\n4. Adresi yazıp onaylayın veya haritadaki konumu kullanın\n5. Koordinat formatını seçin: DMS (derece-dakika-saniye) veya decimal\n6. "Kaydet" butonuna basın\n\nTesisler harita üzerinde özel ikonlarla gösterilir. Tesis ikonuna tıklayınca tesis bilgileri, aktif personel sayısı ve ilgili görevler görüntülenir. Tesis bilgilerini daha sonra düzenleyebilir veya silebilirsiniz.' },
 { q: 'Harita üzerinden ekleme işlemleri', a: 'Harita üzerinden personel, araç, ekipman ve tesis ekleyebilirsiniz:\n\n1. Haritada istediğiniz konuma tıklayın\n2. Açılan menüden eklemek istediğiniz öğeyi seçin: Yeni Personel Ekle, Araç Ekle, Ekipman Ekle veya Tesis Ekle\n3. Gerekli bilgileri doldurun\n4. "Kaydet" butonuna basın\n\nEklenen öğeler harita üzerinde ilgili ikonlarla gösterilir.' },
 { q: 'Harita görünüm seçenekleri', a: 'Harita şu anda Arazi görünümünü destekler:\n\n- Arazi Görünümü: Topografik detayları içeren görünüm\n\nGörünüm değiştirmek için haritanın sağ üst köşesindeki katman butonuna tıklayın. Haritayı tam ekran modunda açmak için genişletme butonunu kullanın.' },
 ],
 },
 {
 icon: Building2, title: 'Tesis Haritası (Live Facility Map)', path: '/harita',
 items: [
 { q: 'Tesis planı nasıl yüklenir?', a: '"Canlı Operasyon & Tesis Haritaları" sayfasında "Tesis Haritası" sekmesine geçin. Tesis planı yüklemek için aşağıdaki adımları izleyin:\n\n1. "Plan Yükle" butonuna tıklayın\n2. Dosya seçiniz - desteklenen formatlar: PNG, JPG, SVG\n3. Plan adı ve kat bilgisini girin (ör: "Ana Fabrika - Zemin Kat")\n4. Planı yükleyin ve boyutlandırma ayarlarını yapın\n5. "Kaydet" ile planı onaylayın\n\nBirden fazla kat planı yükleyebilirsiniz. Katlar arasında geçiş yapmak için üst kısımda yer alan kat seçici butonlarını kullanın. Plan yükledikten sonra üzerine alanlar ve işaretçiler ekleyerek canlı bir tesis haritası oluşturabilirsiniz.\n\nEn iyi sonuç için yüksek çözünürlüklü ve net bir plan görseli kullanmanızı öneririz. SVG formatı yakınlaştırma sırasında en iyi kaliteyi sunar.' },
 { q: 'Alan ve işaretçi nasıl eklenir?', a: '"Düzenle" modunu aktif edip plan üzerine tıklayarak alan veya işaretçi ekleyin. Alan ekleme adımları:\n\n1. "Düzenle" butonuna basın - plan düzenleme moduna geçer\n2. Plan üzerinde istediğiniz noktaya tıklayın\n3. Açılan formda alan bilgilerini doldurun:\n - Tip: Departman, Makine, Depo, Ofis, Ortak Alan, Tehlike Bölgesi vb.\n - Katman: Departmanlar, IoT, Görevler, Stok, Acil Durum\n - Renk ve boyut ayarları\n - İlişkili öğe: Departman, IoT cihaz veya stok kalemi ile bağlantı\n4. "Kaydet" ile alanı onaylayın\n\nOluşturulan alanlar plan üzerinde renk kodlarıyla görüntülenir. Her alana tıklayarak detay bilgilerini görebilir, canlı verileri izleyebilir ve hızlı işlemler yapabilirsiniz.' },
 { q: 'Katmanlar nasıl açılır/kapatılır?', a: 'Haritanın üstündeki katman butonlarıyla farklı veri katmanlarını kontrol edebilirsiniz. Mevcut katmanlar:\n\n- Departmanlar: Departman alanlarını ve personel yoğunluğunu gösterir\n- IoT: Sensör ve cihaz konumlarını ve canlı değerlerini gösterir\n- Görevler: Aktif görevlerin konumlarını gösterir\n- Stok: Stok kalemlerinin depolama konumlarını gösterir\n- Acil Durum: Acil çıkışlar, yangın söndürücüler ve tehlike bölgelerini gösterir\n\nHer katmanı bağımsız olarak açıp kapatabilirsiniz. Birden fazla katmanı aynı anda görüntülemek mümkündür. Katman seçimi tesis haritasının üstündeki toggle butonları ile yapılır.' },
 { q: 'Sektör şablonu nasıl uygulanır?', a: '"Şablon" butonuyla sektörünüze uygun hazır alan yerleşimini seçin. Mevcut şablon kategorileri:\n\n- Üretim: Üretim hatları, kalite kontrol, hammadde deposu, sevkiyat alanı\n- Lojistik: Yük alanı, araç parkı, şoförler odası, dağıtım merkezi\n- Sağlık: Hasta kabul, ameliyathane, eczane, laboratuvar\n- Perakende: Satış alanı, depo, kasa bölümü, müdüriyet\n- Enerji: Kontrol odası, trafo, jeneratör, bakım atölyesi\n- Eğitim: Sınıflar, laboratuvar, kütüphane, yemekhane\n\nŞablon uyguladığında mevcut alanlara dokunulmaz, yeni alanlar eklenir. Şablon alanlarını daha sonra istediğiniz gibi düzenleyebilir, taşıyabilir veya silebilirsiniz.' },
 { q: 'Canlı veri nasıl görüntülenir?', a: 'IoT cihazlarına, departmanlara veya stok kalemlerine bağlanan alanlarda canlı durum rozetleri görürsünüz. Renk kodları:\n\n- Yeşil: Normal - tüm değerler kabul edilebilir aralıkta\n- Sarı: Uyarı - bazı değerler uyarı eşiğine yaklaştı\n- Kırmızı: Kritik - değerler kritik eşiği aştı, acil müdahale gerekli\n- Gri: Bağlantı yok - cihaz çevrimdışı veya veri gelmiyor\n\nBir alana tıklayınca detay penceresi açılır ve şu bilgiler görüntülenir:\n- Canlı sensör değerleri (sıcaklık, nem, basınç vb.)\n- Son 24 saatlik trend grafiği\n- Aktif alarm ve uyarılar\n- O alandaki personel listesi\n- İlişkili görevler ve raporlar' },
 { q: 'Acil durum modu nedir?', a: '"Acil Durum" butonuyla tesis haritası acil durum moduna geçer. Bu modda:\n\n- Tehlike bölgeleri kırmızı parlak sınırlarla vurgulanır\n- Acil çıkış noktaları yeşil yanıp sönen ikonlarla işaretlenir\n- Yangın söndürücüler ve ilk yardım kitleri görüntülenir\n- Diğer normal alanlar soluk görünür, dikkat dağıtıcıları azaltır\n- Kritik alanlarda nabız animasyonu görürsünüz\n\nAcil durum modu gerçek bir acil durumda personelin hızla çıkış ve güvenlik ekipmanlarını bulmasını sağlar. Bu modu tatbikat veya planlama amacıyla da kullanabilirsiniz. Moddayken "Normal Mod" butonuna basarak standart görünüme dönebilirsiniz.' },
 { q: 'OperIQ tesis analizi nasıl yapılır?', a: '"OperIQ" butonuyla tüm tesis için kapsamlı bir AI analizi başlatabilirsiniz. Analiz şu bileşenlerden oluşur:\n\n- Alan Kullanımı Analizi: Hangi alanlar etkin kullanılıyor, hangileri boşta\n- Risk Değerlendirmesi: Potansiyel tehlike ve sorun bölgeleri\n- Verimlilik Önerisi: İş akışı ve yerleşim optimizasyon önerileri\n- Anomali Tespiti: Normal dışı durumlar ve uyarılar\n\nBelirli bir alan için analiz almak için o alana tıklayın ve "OperIQ Analiz" butonuna basın. Alan bazında analiz daha detaylı ve odaklı sonuçlar üretir.\n\nAnaliz sonuçları rapor formatında sunulur - problemli alanlar, önerilen aksiyonlar ve risk seviyesi yer alır. Önerilen aksiyonları doğrudan görev olarak oluşturabilirsiniz.' },
 ],
 },
 {
 icon: Cpu, title: 'IoT Cihaz Yönetimi', path: '/iot',
 items: [
 { q: 'IoT cihaz nasıl eklenir?', a: '"Cihazlar" sayfasından "Yeni Cihaz" butonuyla cihaz eklemek için aşağıdaki adımları izleyin:\n\n1. Cihaz ID: Cihazın benzersiz kimlik numarasını girin\n2. Cihaz Adı: Tanımlayıcı bir isim verin (ör: "Üretim Hattı 1 - Sıcaklık Sensörü")\n3. Cihaz Tipi: Sensör, gateway, aktüatör veya kontrolcü seçin\n4. Protokol: MQTT, HTTP, CoAP veya Modbus protokolünü seçin\n5. Konum: Cihazın fiziksel konumunu belirleyin (tesis haritasındaki alan ile eşleştirebilirsiniz)\n6. Alarm Eşikleri: Her ölçüm değeri için min/max eşikleri tanımlayın\n7. "Kaydet" butonuna basın\n\nCihaz eklendikten sonra bağlantı bilgileri otomatik üretilir. Bu bilgileri cihaz yapılandırmasında kullanarak veri göndermeye başlayabilirsiniz. Cihaz ilk verisini gönderdiğinde durum "Çevrimiçi" olarak güncellenir.' },
 { q: 'Alarm eşikleri nasıl ayarlanır?', a: 'Cihaz detayında her sensör değeri için eşik değerleri tanımlayabilirsiniz. Eşik türleri:\n\n- Minimum Uyarı: Değer bu seviyenin altına düştüğünde sarı uyarı oluşur\n- Minimum Kritik: Değer bu seviyenin altına düştüğünde kırmızı alarm oluşur\n- Maksimum Uyarı: Değer bu seviyeyi aştığında sarı uyarı oluşur\n- Maksimum Kritik: Değer bu seviyeyi aştığında kırmızı alarm oluşur\n\nEşik aşıldığında şu işlemler otomatik gerçekleşir:\n1. Cihaz detayında alarm ikonu görüntülenir\n2. Tesis haritasındaki ilgili alan kırmızı/sarı renk alır\n3. Tanımlanan kişilere bildirim gönderilir (e-posta ve platform bildirimi)\n4. Otomasyon kuralı tanımlanmışsa ilgili aksiyonlar tetiklenir\n\nEşik değerlerini istediğiniz zaman güncelleyebilirsiniz. Geçmiş alarm kayıtlarına cihaz detayındaki "Alarm Geçmişi" sekmesinden ulaşabilirsiniz.' },
 { q: 'Cihaz durum izleme ve geçmiş verileri', a: 'Her IoT cihazının detay sayfasında şu bilgiler bulunur:\n\n- Canlı Durum: Cihazın şu anki durumu (çevrimiçi, çevrimdışı, alarm)\n- Son Değerler: En son alınan sensör değerleri\n- Trend Grafiği: Seçilen zaman aralığındaki veri grafiği\n- Bağlantı Bilgisi: Son iletişim zamanı ve sinyal gücü\n- Alarm Geçmişi: Geçmişteki tüm alarm kayıtları\n\nGeçmiş verileri görüntülemek için:\n1. Cihaz detay sayfasını açın\n2. "Geçmiş Veriler" sekmesine geçin\n3. Tarih aralığını seçin\n4. İstediğiniz sensör değerlerini seçin\n5. Grafik otomatik çizilir - yakınlaştırarak detay görebilirsiniz\n\nGeçmiş verileri CSV veya Excel formatında dışarı aktarabilirsiniz.' },
 { q: 'Cihaz gruplama ve toplu yönetim', a: 'Cihazları gruplar halinde organize edebilirsiniz. Bu özellikle çok sayıda cihazı olan tesislerde işlemleri kolaylaştırır.\n\nGrup oluşturmak için:\n1. "Cihazlar" sayfasında "Gruplar" sekmesine geçin\n2. "Yeni Grup" butonuna basın\n3. Grup adını girin (ör: "Üretim Hattı Sensörleri", "Depo İklimlendirme")\n4. Gruba cihaz ekleyin\n5. "Kaydet" butonuna basın\n\nGrup üzerinden toplu işlemler yapabilirsiniz: toplu alarm eşiği güncelleme, toplu aktif/pasif yapma veya grubun genel sağlık durumunu tek ekranda izleme. Cihaz listesinde grup filtresi ile belirli bir gruba ait cihazları hızla bulabilirsiniz.' },
 { q: 'IoT veri görselleştirme', a: 'IoT verilerini çeşitli grafik tipleriyle görselleştirin:\n\n- Çizgi Grafik: Zaman serisindeki değişimleri takip edin (ör: sıcaklık trendi)\n- Gösterge (Gauge): Anlık değeri kadran üzerinde görün\n- Isı Haritası: Birden fazla cihazın değerlerini renk matrisi ile karşılaştırın\n- Tablo: Tüm cihaz değerlerini satırlar halinde görün\n\nDashboard\'a IoT widgeti eklemek için dashboard düzenleme modunda "IoT Widget" seçeneğini kullanın. Her widget bir veya birden fazla cihazın verilerini gösterebilir. Gerçek zamanlı güncelleme ile veriler canlı olarak akar.' },
 ],
 },
 {
 icon: Package, title: 'Stok Yönetimi', path: '/stok',
 items: [
 { q: 'Stok modülü genel bakış', a: 'Stok yönetimi modülü, işletmenizdeki tüm malzeme, hammadde, yedek parça ve ürünlerin takibini sağlar. Ana ekranda şu bilgiler yer alır:\n\n- Stok Özeti: Toplam kalem sayısı, toplam değer, kritik seviyedeki kalemler\n- Kategori Dağılımı: Stoklarınızın kategorilere göre dağılım grafiği\n- Son Hareketler: En son yapılan giriş ve çıkış işlemleri\n- Uyarılar: Minimum stok seviyesinin altına düşen kalemler\n\nSol taraftaki kategori ağacından belirli kategorilere hızla erişebilirsiniz. Üst kısımdaki arama çubuğu ile stok kalemi adı, kodu veya barkod numarası ile arama yapabilirsiniz.' },
 { q: 'Yeni stok kalemi nasıl eklenir?', a: 'Stok sayfasında "Yeni Kalem" butonuna basarak stok kalemi ekleyin:\n\n1. Kalem Adı: Ürünün veya malzemenin adını girin\n2. Stok Kodu: Benzersiz bir stok kodu belirleyin (otomatik üretim de mümkün)\n3. Kategori: Uygun kategoriyi seçin veya yeni kategori oluşturun\n4. Birim: Adet, kg, litre, metre, kutu vb. birimi seçin\n5. Minimum Stok Seviyesi: Uyarı için alt limit belirleyin\n6. Maksimum Stok Seviyesi: Üst limit (opsiyonel)\n7. Depo/Lokasyon: Fiziksel depolama konumunu seçin\n8. Barkod: Varsa barkod numarasını girin\n9. Tedarikçi: Varsayılan tedarikçiyi seçin\n\nKalem oluşturulduktan sonra fotoğraf ekleyebilir, ek notlar girebilir ve tesis haritasında konumunu işaretleyebilirsiniz.' },
 { q: 'Stok hareketi (giriş/çıkış) nasıl yapılır?', a: 'Stok hareketi kaydetmek için iki yöntem vardır:\n\nTek Kalem Hareketi:\n1. Stok kalemi detay sayfasını açın\n2. "Hareket Ekle" butonuna basın\n3. Hareket tipini seçin: Giriş (satın alma, iade, üretim) veya Çıkış (kullanım, sevkiyat, fire)\n4. Miktarı girin\n5. Açıklama ve referans numarası ekleyin\n6. "Kaydet" ile hareketi onaylayın\n\nToplu Hareket:\n1. Stok sayfasında "Toplu Hareket" butonuna basın\n2. Excel şablonunu indirin veya barkod okuyucu ile kalemleri taratın\n3. Her kalem için miktar ve hareket tipini belirleyin\n4. Önizlemeyi kontrol edin\n5. "Onayla" ile tüm hareketleri kaydedin\n\nHer hareket otomatik zaman damgası ve kullanıcı bilgisi ile kaydedilir. Hareketleri geri almak mümkün değildir - hatalı giriş için ters hareket oluşturmanız gerekir.' },
 { q: 'Stok uyarıları nasıl çalışır?', a: 'Minimum stok seviyesi tanımlanan kalemlerin stok miktarı bu seviyenin altına düştüğünde otomatik uyarı oluşur. Uyarı sistemi şu şekilde çalışır:\n\n1. Stok miktarı minimum seviyenin altına düşer\n2. Sistem otomatik uyarı oluşturur ve ilgili kişilere bildirim gönderir\n3. Stok panelinde "Kritik Stok" bölümünde kırmızı ile işaretlenir\n4. Dashboard\'daki stok widgetında uyarı görüntülenir\n5. Otomasyon kuralı tanımlanmışsa otomatik satınalma talebi oluşabilir\n\nUyarı seviyeleri:\n- Sarı Uyarı: Stok miktarı minimum seviyeye yaklaştı (minimum + %20)\n- Kırmızı Alarm: Stok miktarı minimum seviyenin altına düştü\n- Sıfır Stok: Stok tamamen tükendi\n\nUyarı bildirimlerini kimlerin alacağını stok ayarlarından yapılandırabilirsiniz.' },
 { q: 'Envanter nasıl yüklenir (Excel/CSV)?', a: 'Mevcut envanterinizi toplu olarak platforma yüklemek için:\n\n1. "Stok" sayfasında "İçerik Aktar" butonuna basın\n2. "Şablon İndir" ile boş şablon dosyasını alın\n3. Şablonu Excel veya CSV formatında doldurun. Gerekli alanlar: Kalem Adı, Stok Kodu, Kategori, Birim, Miktar\n4. Doldurulmuş dosyayı yükleyin\n5. OperIQ sütunları otomatik eşleştirir - eşleştirme önizlemesini kontrol edin\n6. Hatalı satırlar varsa düzeltme önerileri görüntülenir\n7. "Kaydet" ile tüm kalemleri içe aktarın\n\nMevcut stok kalemlerini güncellemek için de aynı yöntemi kullanabilirsiniz - stok kodu eşleşen kalemler güncellenir, yeni kodlar ise yeni kalem olarak eklenir.' },
 { q: 'Stok raporu ve analiz', a: 'Stok modülünde çeşitli raporlar ve analizler mevcuttur:\n\n- Stok Durum Raporu: Tüm kalemlerin güncel stok miktarları ve değerleri\n- Hareket Raporu: Belirli tarih aralığındaki tüm giriş ve çıkış hareketleri\n- Tüketim Analizi: Kalemlerin tüketim hızı ve trendi\n- Kritik Stok Raporu: Minimum seviyenin altındaki veya yaklaşan kalemler\n- Değer Raporu: Kategorilere göre stok değeri dağılımı\n\nRaporları PDF veya Excel formatında indirebilirsiniz. OperIQ ile stok verilerinize dayalı tahminleme ve optimizasyon önerileri alabilirsiniz - örneğin "Hangi kalemler önümüzdeki ay içinde tükenebilir?" sorusunu sorabilirsiniz.' },
 ],
 },
 {
 icon: Package, title: 'AssetIQ (QR + Stok Zekası)', path: '/envanter-zeka',
 items: [
 { q: 'AssetIQ modülü nedir?', a: 'AssetIQ, QR kod sistemi ile stok yönetimini derinlemesine entegre eden, operasyonel süreçlerle bağlantılı, yapay zeka destekli bir envanter ve tüketim yönetim sistemidir.\n\nModül şu temel özellikleri içerir:\n- QR Kod Yönetimi: Her stok kalemi ve lokasyon için QR kod oluşturma ve tarama\n- Stok Lokasyonları: Hiyerarşik depo/raf/bölme yapısı\n- Parti/Lot Takibi: Üretim tarihi, son kullanma tarihi, tedarikçi bilgisi\n- Gelişmiş Hareketler: 7 farklı hareket tipi (Giriş, Çıkış, Kullanım, Fire, Transfer, Sayım, Rezervasyon)\n- Görev Bazlı Stok Ayırma: Görevler için stok rezervasyonu\n- Hızlı Tüketim: Saha çalışanları için tek dokunuşla stok düşme\n- OperIQ Analiz: Sektör bazlı yapay zeka destekli stok analizi\n- Satın Alma Sorumlusu: Kritik stok bildirimlerinin doğru kişilere ulaşması' },
 { q: 'QR kod nasıl oluşturulur ve kullanılır?', a: 'QR kodları oluşturmak için:\n1. "AssetIQ" sayfasında "QR Yönetimi" sekmesine gidin\n2. "Yeni QR" butonuna basın\n3. Varlık tipini seçin (Stok Kalemi, Lokasyon, Ekipman, IoT Cihaz, Tesis Alanı)\n4. İlişkili varlığı seçin\n5. Opsiyonel etiket ekleyin\n6. "QR Oluştur" butonuna basın\n\nQR taramak için:\n- "QR Tara" bölümüne QR kodunu girin veya mobil uygulamadan okutun\n- Sistem otomatik olarak bağlı varlığı açar\n- Sektör şablonuna göre uygun ekran ve aksiyonlar görüntülenir\n\nÖrnekler:\n- Üretimde QR okutunca makine bağlı parçalar ekranı\n- Sağlıkta QR okutunca ilaç/tıbbi malzeme ekranı\n- Perakendede QR okutunca raf stoğu ekranı' },
 { q: 'Stok lokasyonları nasıl yönetilir?', a: 'Lokasyonlar hiyerarşik bir yapıda organize edilir (Depo > Raf > Bölme).\n\n1. "Lokasyonlar" sekmesine gidin\n2. "Yeni Lokasyon" butonuna basın\n3. Lokasyon bilgilerini girin: Ad, Kod, Kategori, Departman\n4. Üst lokasyon seçerek alt lokasyon oluşturun\n\nLokasyon kategorileri:\n- Ana Depo, Raf, Üretim Hattı, Soğuk Depo, Bakım Deposu, Araç, Dağıtım Noktası, Servis Alanı, Laboratuvar\n\nHer lokasyondaki stok kalemleri ve miktarları görüntülenebilir. Lokasyon ağacı görünümüyle tüm yapı tek bakışta görülür.' },
 { q: 'Parti/Lot takibi nasıl yapılır?', a: 'Batch/Lot yönetimi özellikle gıda, sağlık, kimya ve FMCG sektörlerinde zorunludur.\n\n1. "Parti/Lot" sekmesine gidin\n2. "Yeni Parti" butonuna basın\n3. Stok kalemini seçin\n4. Parti numarasını girin (ör: LOT-2026-001)\n5. Üretim tarihi ve son kullanma tarihini girin\n6. Tedarikçi ve lokasyon bilgilerini ekleyin\n\nSistem otomatik olarak:\n- Son kullanma tarihi yaklaşan partileri (30 gün) uyarı olarak işaretler\n- Son kullanma tarihi geçmiş partilerin durumunu günceller\n- Dashboard\'da "SKT Yaklaşan Partiler" listesini gösterir' },
 { q: 'Hızlı tüketim modu nasıl kullanılır?', a: 'Saha çalışanları için minimum input ile hızlı stok düşümü:\n\n1. QR kodu okutun veya "Hızlı Tüketim" butonuna basın\n2. Stok kalemini seçin\n3. Miktar seçin (+1, +5, +10 veya özel miktar)\n4. "Kaydet" ile tek dokunuşta stok düşümü yapın\n\nHızlı tüketim otomatik olarak:\n- InventoryTransaction kaydeder\n- ConsumptionEvent oluşturur\n- StockMovement (legacy) günceller\n- Kritik seviye kontrol edip gerekirse uyarı tetikler\n\nBu özellik sektör bazlı farklı isimlerle gösterilir (üretimde "Hızlı Kullanım", sağlıkta "Hızlı Sarf Düşüm", perakendede "Hızlı Raf Eksiltme").' },
 { q: 'Stok rezervasyonu nasıl yapılır?', a: 'Görevler için stok ayırma işlemleri:\n\n1. "Rezervasyonlar" sekmesine gidin\n2. "Yeni Rezervasyon" butonuna basın\n3. Stok kalemini ve miktarını seçin\n4. Hangi görev için olduğunu belirtin\n5. Son geçerlilik tarihi ekleyin (opsiyonel)\n\nRezervasyonlar stok miktarından düşülmez, ancak kullanılabilir miktar hesaplamasında dikkate alınır. Görev tamamlandığında rezervasyon otomatik kullanılır. Süresi dolan rezervasyonlar otomatik kapatılır.' },
 { q: 'Satın alma sorumlusu nasıl tanımlanır?', a: 'Kritik stok bildirimlerinin doğru kişilere ulaşması için:\n\n1. "Satın Alma" sekmesine gidin\n2. "Sorumlu Ekle" butonuna basın\n3. Kullanıcıyı seçin\n4. Sorumluluk tipini belirleyin: Ana Satın Alma Sorumlusu, Yedek Sorumlu veya Key Account Manager\n5. Sorumlu olduğu departmanları seçin (boş bırakarak tüm şirket genelini kaplayabilir)\n\nKritik veya risk gösteren stok durumunda:\n- Stoğun olduğu departmanın müdürüne bildirim ve mesaj gider\n- İlgili satın alma sorumlularına bildirim ve mesaj gider\n- Satın alma departmanı yoksa key account manager\'a bildirim gider' },
 { q: 'Sektör şablonları ve terminoloji', a: 'AssetIQ modülü 10 farklı sektöre uyarlanabilir terminoloji sunar:\n\n1. Üretim: Yedek Parça, Sarf Malzeme, Üretim Hattı\n2. Gıda: Hammadde, Ambalaj, Soğuk Depo, Parti/Lot\n3. Sağlık: Tıbbi Malzeme, İlaç, İlaç Odası, Hasta Kullanımı\n4. Lojistik: Koli, Palet, Sevkiyat Çıkışı, Dağıtım Noktası\n5. Perakende: Ürün, Raf Stoğu, Satış Çıkışı, Mağaza Deposu\n6. Kamu: Ekipman, Teknik Malzeme, Hizmet Binası\n7. Eğitim: Eğitim Materyali, Laboratuvar Sarfı\n8. Enerji: Kritik Parça, Trafo Sahası, Bakım Kullanımı\n9. HoReCa: Mutfak Sarfı, Servis Malzemesi, Soğuk Oda\n10. IT: Network Ekipmanı, Server Odası, Kurulum Çıkışı\n\nŞirketinizin sektörü seçildiğinde tüm ekranlar, hareket isimleri ve OperIQ yorumları otomatik olarak sektör diline uyarlanır.' },
 { q: 'IoT cihaz sorumlusu ve bildirim sistemi', a: 'Her IoT cihazına bir veya birden fazla sorumlu atanabilir:\n\n1. "IoT Sorumlu" bölümüne gidin\n2. Cihazı ve sorumlu kişiyi seçin\n3. Sorumluluk tipini belirleyin (Ana veya Yedek)\n4. Bildirim tercihlerini ayarlayın:\n - Alert durumunda bildirim\n - Kritik durumda bildirim\n - Offline durumda bildirim\n - Rutin durum raporu (günde 2 kere: 09:00 ve 17:00)\n\nRisk veya kritik durumda sorumlu kişiye otomatik bildirim ve mesaj gider. Günde 2 kere tüm sorumluların sorumlu olduğu cihazların genel durum özeti gönderilir.' },
 { q: 'OperIQ envanter analizi', a: 'OperIQ, sektör bağlamına göre stok verilerini analiz eder:\n\n1. "OperIQ Zeka" sekmesine gidin\n2. "Analiz Et" butonuna basın\n3. Sistem şu analizleri yapar:\n - Hızlı tükenen kalemler ve risk değerlendirmesi\n - Anormal tüketim kalıpları\n - Tükenme tahmini (kaç gün yeter)\n - Batch/lot son kullanma riskleri\n - IoT cihaz durumları ile stok ilişkisi\n - Fazla stok tespiti\n - Görev-stok uyumluluğu\n - Tedarik planlama önerileri\n\nHer içgörü aksiyon odaklıdır ve sektör terminolojisinde sunulur. Örneğin üretimde "Rulman tüketimi son 10 günde %40 arttı", sağlıkta "Bu tıbbi sarf beklenenden hızlı tüketildi" gibi.' },
 ],
 },
 {
 icon: FolderOpen, title: 'Dosya Yönetimi', path: '/dosyalar',
 items: [
 { q: 'Dosya nasıl yüklenir?', a: 'Dosya yönetimi modülü ile tüm kurumsal dokümanlarınızı organize edebilirsiniz. Dosya yüklemek için:\n\n1. Sol menüden "Dosyalar" a gidin\n2. Yüklemek istediğiniz klasöre girin (veya yeni klasör oluşturun)\n3. "Dosya Yükle" butonuna basın veya dosyaları doğrudan sürükleyip bırakın\n4. Desteklenen formatlar: Word (.docx), Excel (.xlsx), PDF (.pdf), görseller (JPG, PNG, GIF), metin (.txt, .csv)\n5. Maksimum dosya boyutu: 50 MB\n6. Birden fazla dosyayı aynı anda yükleyebilirsiniz\n\nYüklenen her dosya için yükleyen kişi, tarih ve boyut bilgisi otomatik kaydedilir. Dosyalara açıklama ve etiket ekleyerek aranabilirliğini artırabilirsiniz.' },
 { q: 'Klasör yapısı ve organizasyon', a: 'Dosyalarınızı klasör hiyerarşisi ile düzenleyin:\n\n1. "Yeni Klasör" butonuna basın\n2. Klasör adını girin\n3. Üst klasör seçin (alt klasör oluşturmak için)\n4. Erişim yetkisini belirleyin (tüm kullanıcılar veya belirli departmanlar)\n\nÖnerdiğimiz klasör yapısı:\n- Genel Dokümanlar: Şirket genelinde paylaşılan belgeler\n- Departman Dosyaları: Her departman için ayrı klasör\n- Proje Dosyaları: Projelere özel dokümanlar\n- Şablonlar: Form şablonları ve standart dokümanlar\n- Arşiv: Eski ve tamamlanmış proje dosyaları\n\nKlasörleri sürükleyerek taşıyabilir, yeniden adlandırabilir veya silebilirsiniz (içindeki dosyalar çöp kutusuna taşınır).' },
 { q: 'Dosya görüntüleme ve ön izleme', a: 'Dosya adına tıklayarak içeriği platform içerisinde görüntüleyebilirsiniz. Ön izleme desteklenen formatlar:\n\n- PDF: Sayfa sayfa görüntüleme, yakınlaştırma, arama\n- Word (.docx): Doküman içeriği formatlarıyla birlikte görüntülenir\n- Excel (.xlsx): Tablo görünümünde, sayfa sekmeleri ile\n- Görseller (JPG, PNG, GIF): Tam boyut görüntüleme, yakınlaştırma\n- Metin Dosyaları (.txt, .csv): Düz metin olarak görüntüleme\n\nÖn izleme ekranında şu işlemler mevcuttur:\n- İndir: Dosyayı bilgisayarınıza indirin\n- Paylaş: Dosya linkini başka kullanıcılarla paylaşın\n- Yazdır: Dosyayı doğrudan yazıcıya gönderin\n- Sil: Dosyayı çöp kutusuna gönderin' },
 { q: 'Dosya arama ve filtreleme', a: 'Dosya modülündeki arama özellikleri:\n\n- Hızlı Arama: Üst kısımdaki arama çubuğuna dosya adını yazın\n- Tip Filtresi: Belirli dosya türlerini filtreleyin (PDF, Excel, Görsel vb.)\n- Tarih Filtresi: Belirli zaman aralığında yüklenen dosyaları bulun\n- Yükleyen Kişi: Belirli bir kullanıcının yüklediği dosyaları listeleyin\n- Etiket: Dosyalara eklenmiş etiketlere göre filtreleyin\n\nArama sonuçları dosya adı, boyut, yüklenme tarihi ve konumu ile birlikte listelenir. Sonuca tıklayarak doğrudan dosyayı görüntüleyebilirsiniz.' },
 ],
 },
 {
 icon: Zap, title: 'Otomasyon & Kurallar', path: '/otomasyon',
 items: [
 { q: 'Otomasyon kuralı nasıl oluşturulur?', a: '"Otomasyon" sayfasından adım adım sihirbaz ile otomasyon kuralı tanımlayın. Kural oluşturma adımları:\n\n1. Tetikleyici (Trigger) seçin: Kuralı başlatacak olayı belirleyin\n - Görev gecikti\n - Rapor oluşturuldu\n - Stok seviyesi düştü\n - IoT alarm tetiklendi\n - KPI hedefi aşıldı veya geriledi\n - Belirli bir zaman geldi (zamanlanmış)\n\n2. Koşul (Condition) ekleyin (opsiyonel): Tetikleyicinin hangi koşullarda çalışacağını belirleyin\n - Departman filtresi\n - Öncelik seviyesi\n - Belirli kullanıcı veya rol\n\n3. Aksiyon (Action) tanımlayın: Tetiklendiğinde ne olacağını belirleyin\n - Bildirim gönder (platform, e-posta)\n - Görev oluştur\n - Durum güncelle\n - Rapor oluştur\n - OperIQ analizi başlat\n\n4. Kuralı test edin ve aktif hale getirin\n\nÖrnek kural: "Kritik öncelikli görev 24 saat geciktiyse, departman müdürüne e-posta gönder ve üst yöneticiye bildirim at"' },
 { q: 'Otomasyon kurallarını yönetme', a: 'Mevcut kuralları yönetmek için "Otomasyon" sayfasındaki kural listesini kullanın:\n\n- Aktif/Pasif: Her kuralın yanındaki toggle ile kuralı aktif veya pasif yapabilirsiniz\n- Düzenleme: Kural satırına tıklayarak detaylarını değiştirin\n- Kopyalama: Mevcut bir kuralı kopyalayarak benzer yeni kural oluşturun\n- Silme: Artık gerekmeyen kuralları silin\n- Çalışma Geçmişi: Her kuralın ne zaman tetiklendiği ve ne sonuç verdiği kayıtlıdır\n\nKurallar öncelik sırasına göre işlenir. Aynı tetikleyiciye sahip birden fazla kural varsa hepsi ayrı ayrı çalışır. Kuralların çalışma geçmişini inceleyerek beklenmedik davranışları tespit edebilirsiniz.' },
 { q: 'Hazır otomasyon şablonları', a: 'Hızlı başlamak için hazır otomasyon şablonlarını kullanabilirsiniz. Sol taraftaki "Şablonlar" bölümünde sık kullanılan senaryolar mevcuttur:\n\n- Görev Gecikme Uyarısı: Geciken görevler için otomatik bildirim\n- Kritik Rapor Eskalasyonu: Kritik şiddetteki raporların üst yönetime iletilmesi\n- Stok Yenileme Talebi: Minimum stok altına düşen kalemler için satın alma talebi\n- IoT Alarm Yanıtı: Sensör alarmı tetiklendiğinde görev oluşturma\n- Haftalık Özet: Her pazartesi günlük özet rapor oluşturma\n\nŞablonu seçin, gerekli ayarları yapın (departman, kişiler vb.) ve "Aktif Et" butonuna basın. Şablonları temel alarak kendi özel kurallarınızı da oluşturabilirsiniz.' },
 { q: 'Otomasyon logları ve hata ayıklama', a: 'Her otomasyon kuralı çalıştığında detaylı log kaydı oluşturulur. Logları incelemek için:\n\n1. Otomasyon sayfasında ilgili kurala tıklayın\n2. "Çalışma Geçmişi" sekmesine geçin\n3. Her çalışma için tarih, tetikleyici bilgisi, koşul sonucu ve aksiyon durumu görüntülenir\n\nLog durumları:\n- Başarılı (yeşil): Kural başarıyla çalıştı ve aksiyon tamamlandı\n- Atlandı (sarı): Kural tetiklendi ama koşul sağlanmadı\n- Hata (kırmızı): Kural çalıştı ama aksiyonda hata oluştu\n\nHata durumlarında hata detayını inceleyerek sorunu teşhis edebilirsiniz. Sık karşılaşılan hatalar: hedef kullanıcı bulunamadı, e-posta gönderilemedi veya hedef kaynak mevcut değil.' },
 ],
 },
 {
 icon: Workflow, title: 'İş Akışları (Workflows)', path: '/otomasyon',
 items: [
 { q: 'İş akışı nedir ve ne işe yarar?', a: 'İş akışları, birden fazla adımdan oluşan ve belirli bir sıraya ile ilerlemesi gereken iş süreçlerini dijitalleştirmenize olanak tanır. Örneğin bir satın alma talebi süreci şu adımları içerebilir: talep oluşturma, şef onay, müdür onay, satın alma, teslim alma, kalite kontrol.\n\nİş akışlarının faydaları:\n- Süreçler standartlaşır ve herkes aynı adımları izler\n- Her adımda kimin ne yapacağı nettir\n- Onay mekanizmaları ile kontrol sağlanır\n- Sürecin hangi aşamada olduğu anlık görüntülenir\n- Geciken adımlar için otomatik hatırlatma gönderilir\n- Geçmiş akış kayıtları ile performans analizi yapılır' },
 { q: 'Yeni iş akışı nasıl oluşturulur?', a: '"İş Akışları" sayfasında "Yeni Akış" butonuna basın. İş akışı tasarımcısı açılır. Adımları:\n\n1. Akış Adı: Süreci tanımlayan bir isim verin (ör: "Satın Alma Talebi", "İzin Başvurusu")\n2. Başlangıç Koşulu: Akışın nasıl başlatılacağını seçin (manuel, otomatik tetikleme)\n3. Adımlar Ekleyin: Her adım için:\n - Adım adı ve açıklaması\n - Sorumlu kişi veya rol (ör: "Departman Müdürü")\n - Adım tipi: Onay, Bilgi Girişi, Bildirim, Dallanma veya Paralel İşlem\n - Tamamlanma süresi (opsiyonel SLA)\n4. Bağlantıları Tanımlayın: Adımların hangi sıraya ile ilerleyeceğini belirleyin\n5. Dallanma: "Onaylandı" ise bir yol, "Reddedildi" ise başka bir yol tanımlayabilirsiniz\n6. "Kaydet ve Aktif Et" ile akışı yayınlayın\n\nAkış tasarımcısında sürükle-bırak ile adımlar ekleyip sıralarını değiştirebilirsiniz.' },
 { q: 'İş akışı şablonları', a: 'Hızlıca başlamak için hazır iş akışı şablonları mevcuttur:\n\n- Satın Alma Talebi: Talep - Şef Onay - Müdür Onay - Satınalma - Teslim Alma\n- İzin Başvurusu: Başvuru - Yönetici Onay - İK Onay - Kayıt\n- Bakım Talebi: Arıza Bildirimi - Önceliklendirme - Atama - Uygulama - Kontrol\n- Yeni Personel İşe Giriş: Doküman Toplama - İK Kayıt - IT Hesap Açma - Eğitim - Departman Atama\n- Kalite Kontrol: Numune Alma - Test - Değerlendirme - Onay/Red\n\nŞablon seçmek için:\n1. "Yeni Akış" butonuna basın\n2. "Şablondan Oluştur" sekmesine geçin\n3. İstediğiniz şablonu seçin\n4. Adımları ihtiyacınıza göre düzenleyin\n5. Kaydedin ve aktif edin\n\nŞablonlar iyi bir başlangıç noktasıdır - üzerine ekleme ve düzenleme yaparak kendi süreçlerinize uyarlayın.' },
 { q: 'Çalışan iş akışı örneklerini takip etme', a: 'Aktif iş akışı örneklerini (çalışan süreçler) takip etmek için "İş Akışları" sayfasındaki "Çalışan Akışlar" sekmesine geçin. Burada şu bilgiler görüntülenir:\n\n- Akış Adı ve Başlatan Kişi\n- Mevcut Adım: Sürecin hangi aşamada olduğu\n- Sorumlu Kişi: Şu an aksiyonu beklenen kişi\n- Başlama Tarihi ve Süre\n- Durum: Devam Ediyor, Tamamlandı, Beklemede, İptal\n\nBir akış örneğine tıklayarak detaylı zaman çizelgesini görebilirsiniz. Her adımda kimin ne zaman ne yaptığını, harcanan süreyi ve varsa eklenen notları inceleyebilirsiniz.\n\nBeklemede olan adımınız varsa bildirim alırsınız. İlgili adıma tıklayarak onay verin, reddedin veya bilgi girin.' },
 { q: 'İş akışı raporları ve performans', a: 'İş akışı performansını analiz etmek için şu raporlara erişebilirsiniz:\n\n- Ortalama Tamamlanma Süresi: Her akış tipi için ortalama tamamlanma süresi\n- Darboğaz Analizi: En uzun süren adımlar ve bekleme noktaları\n- Tamamlanma Oranı: Başarıyla tamamlanan ve iptal edilen akış oranları\n- Kişi Bazında Performans: Her kullanıcının onay/red süresi ve sayısı\n\nBu raporlar iş süreçlerinizdeki verimsizlikleri tespit etmenize ve iyileştirmeler yapmanıza yardımcı olur. OperIQ\'ya "İş akışlarımda darboğazlar nerede?" diye sorarak AI destekli analiz alabilirsiniz.' },
 ],
 },
 {
 icon: Bell, title: 'Bildirimler',
 items: [
 { q: 'Bildirimler nasıl görüntülenir?', a: 'Bildirimlere erişmenin birden fazla yolu vardır:\n\n- Üst Bar: Sağ üstteki çan ikonuna tıklayın - okunmamış bildirimler kırmızı daire ile gösterilir\n- Bildirim Paneli: Çan ikonuna tıklayınca açılan panelde son bildirimler listelenir\n- Bildirim Sayfası: "Tüm Bildirimleri Gör" linkine tıklayarak tam sayfa bildirim listesine ulaşın\n\nBildirim türleri:\n- Görev Bildirimi: Size atanan yeni görev, durum değişikliği, yorum eklenmesi\n- Rapor Bildirimi: Yeni rapor, durum güncelleme, OperIQ analiz sonucu\n- IoT Alarm: Sensör eşik aşımı, cihaz çevrimdışı uyarısı\n- Stok Uyarısı: Minimum stok seviyesi altına düşme\n- İş Akışı: Onay bekleyen adım, akış tamamlanma\n- Sistem: Platform güncelleme, bakım duyurusu' },
 { q: 'Bildirim tercihlerini ayarlama', a: 'Hangi bildirimleri alacağınızı ve nasıl alacağınızı profil ayarlarından yapılandırabilirsiniz:\n\n1. Sağ üstteki profil ikonunuza tıklayın\n2. "Bildirim Tercihleri" bölümüne gidin\n3. Her bildirim kategorisi için şu kanalları ayarlayın:\n - Platform Bildirimi: Üst bardaki çan ikonu üzerinden\n - E-posta: Giriş e-postanıza gönderilir\n - Her ikisi: Hem platform hem e-posta ile bildirim alın\n - Kapalı: Bu kategori için bildirim almayın\n\nKategoriler: Görevler, Raporlar, IoT Alarmlar, Stok Uyarıları, İş Akışları, Mesajlar, Sistem Duyuruları\n\nÖneri: Kritik IoT alarmları ve görev atamaları için hem platform hem e-posta bildirimini açık tutmanızı tavsiye ederiz. Daha az öncelikli bildirimler için sadece platform bildirimini kullanabilirsiniz.' },
 { q: 'Bildirimleri okundu olarak işaretleme', a: 'Bildirimleri yönetmek için şu işlemleri yapabilirsiniz:\n\n- Tek Bildirim: Bildirim kartına tıklayarak okundu olarak işaretlenir, kart rengi değişir ve bildirim sayısı azalır\n- Toplu İşaretleme: Bildirim panelinin üstündeki "Tümünü Okundu İşaretle" butonuyla tüm bildirimleri okundu yapın\n\nOkunmamış bildirim sayısı üst bardaki çan ikonunun yanında kırmızı daire içinde gösterilir. Yeni bildirim geldiğinde ses çalar ve çan ikonu animasyonlu olarak titrer.' },
 { q: 'E-posta bildirimleri ve özetler', a: 'Platform içerisindeki bildirimlere ek olarak e-posta üzerinden de bilgilendirme alabilirsiniz:\n\n- Anlık E-posta: Kritik bildirimlerde anlık e-posta gönderilir\n- Günlük Özet: Her gün sabah saat 08:00\'de önceki günün özetini içeren e-posta\n- Haftalık Özet: Her pazartesi sabahı haftalık performans özetini içeren e-posta\n\nE-posta bildirimlerini profil ayarlarından açıp kapatabilirsiniz. E-postalardaki "Platforma Git" butonu ile doğrudan ilgili sayfaya yönlendirilirsiniz.\n\nNot: E-posta bildirimlerinin gelmesi için geçerli bir e-posta adresinin kayıtlı olması gerekir. Spam klasörünüzü de kontrol etmeyi unutmayın.' },
 ],
 },
 {
 icon: Lock, title: 'Güvenlik & Yetkilendirme',
 items: [
 { q: 'Yetki sistemi nasıl çalışır?', a: 'ActLedger\'in yetki sistemi 8 seviyeli bir hiyerarşi üzerine kurulmuştur. Her kullanıcıya atanan rol, platform içerisinde ne görebileceğini ve ne yapabileceğini belirler.\n\nTemel prensipler:\n- Her üst seviye, altındaki tüm seviyelerin yetkilerini otomatik olarak içerir\n- Departman bazında erişim sınırlaması vardır - kullanıcılar yalnızca kendi departmanlarının verilerini görür (yönetici rolleri hariç)\n- Bazı işlemler (kullanıcı ekleme, otomasyon oluşturma, ayarlar değiştirme) yalnızca belirli rol seviyelerinde mümkündür\n- Tüm erişim ve işlem kayıtları loglanır (denetim izi)\n\nRol ataması Super Admin veya Genel Müdür tarafından yapılır. Bir kullanıcının rolünü değiştirmek için "Kullanıcılar" sayfasından kullanıcı profilini düzenleyin.' },
 { q: 'Her rol ne yapabilir?', a: 'Detaylı rol yetki tablosu:\n\nİşçi (Seviye 1):\n- Kendisine atanan görevleri görebilir ve tamamlayabilir\n- Form doldurabilir\n- Kendi profilini görebilir\n\nTeknisyen (Seviye 2):\n- İşçi yetkilerine ek olarak saha raporu oluşturabilir\n- IoT verilerini görebilir (salt okunur)\n\nUsta (Seviye 3):\n- Görev oluşturabilir ve kendi ekibine atayabilir\n- Stok görüntüleme\n\nSüpervizör (Seviye 4):\n- Departmanındaki tüm görev ve raporları görebilir\n- Stok hareketi yapabilir\n- Dosya yükleme ve paylaşma\n\nŞef (Seviye 5):\n- Departman KPI\'larını yönetebilir\n- İş akışı oluşturabilir\n- Raporları onaylayabilir\n\nMüdür (Seviye 6):\n- Birden fazla departmanı yönetebilir\n- Kullanıcı ekleyebilir\n- Otomasyon kuralı oluşturabilir\n\nDirektör (Seviye 7):\n- Tüm departmanlara tam erişim\n- Tesis haritası yönetimi\n- Gelişmiş raporlama\n\nGenel Müdür (Seviye 8):\n- Tam yetki - tüm modüllere ve sistem ayarlarına erişim' },
 { q: 'Şifre güvenliği ve politikaları', a: 'ActLedger güçlü şifre politikası uygular:\n\n- Minimum 8 karakter uzunluk\n- En az 1 büyük harf, 1 küçük harf, 1 rakam ve 1 özel karakter\n- Son 5 şifrenin tekrar kullanılması engellenir\n- 90 günde bir şifre değiştirme hatırlatması\n\nŞifre güvenliği için öneriler:\n- Kolay tahmin edilebilecek şifreler kullanmayın (doğum tarihi, isim, "123456" vb.)\n- Her platform için farklı şifre kullanın\n- Şifrenizi başkası ile paylaşmayın\n- Şifre yöneticisi uygulaması kullanmanızı öneririz\n\nŞifrenizi unuttuysanız yöneticinizden (Key Account Manager) yeni şifre talep edin. Platform üzerinde şifre sıfırlama sadece yönetici tarafından yapılabilir.' },
 { q: 'Oturum güvenliği ve çıkış yapma', a: 'Platformda oturum güvenliği şu şekilde çalışır:\n\n- Oturum Süresi: Ayarlar > Güvenlik bölümünden 4, 8 veya 24 saat olarak belirlenebilir\n- Güvenli Çıkış: Sağ üstteki profil menüsünden "Çıkış Yap" butonuna basarak oturumunuzu güvenli şekilde kapatın\n- IP Kısıtlaması (Opsiyonel): Ayarlar > Güvenlik bölümünden belirli IP adreslerinden erişimi sınırlandırabilirsiniz\n\nŞüpheli bir giriş fark ederseniz:\n1. Hemen şifrenizi değiştirin\n2. Yöneticinize bildirin' },
 ],
 },
 {
 icon: MessageSquare, title: 'Mobil Merkez',
 items: [
 { q: 'Mobil Merkez nedir?', a: 'Mobil Merkez, platform içerisindeki mesajlaşma ve iletişim modülüdür. Sol menüden "Mesajlar" bölümüne giderek erişebilirsiniz.\n\nMobil Merkez şu özellikleri sunar:\n- Doğrudan mesajlaşma: Kullanıcılarla birebir mesaj gönderin\n- Departman mesajları: Departman bazlı grup mesajlaşma\n- Genel duyurular (broadcast): Tüm şirkete yayınlanan mesajlar\n- Gerçek zamanlı iletişim: Mesajlar anında iletilir' },
 { q: 'Mesaj nasıl gönderilir?', a: '"Yeni Mesaj" butonuna basın ve alıcı seçin:\n\n1. Doğrudan mesaj: Belirli bir kullanıcıya birebir mesaj gönderin\n2. Departman mesajı: Departman seçin, tüm üyeler alır\n3. Genel duyuru (broadcast): Tüm şirket çalışanlarına yayınlayın\n\nMesajınızı yazın ve "Gönder" butonuna basın. Mesajlar anında iletilir ve alıcıya bildirim gönderilir.' },
 { q: 'Mesaj geçmişi ve arama', a: 'Tüm mesajlarınız konuşmalar halinde saklanır. Bir kişiyle olan tüm yazışmanız kronolojik sırada görüntülenir.\n\nMesaj aramak için mesajlar sayfasının üstündeki arama çubuğuna anahtar kelime yazın. Sonuca tıklayarak ilgili konuşmaya yönlendirilirsiniz.' },
 { q: 'Grup mesajları ve departman iletişimi', a: 'Birden fazla kişiye aynı anda mesaj göndermek için departman mesajlaşmayı veya genel duyuru (broadcast) özelliğini kullanın.\n\nDepartman bazlı mesajlaşma için departman seçin - o departmandaki tüm kullanıcılar mesajı alır. Genel duyuru ile tüm şirket çalışanlarına ulaşabilirsiniz.' },
 ],
 },
 {
 icon: Shield, title: 'Kısayollar & İpuçları',
 items: [
 { q: 'Klavye kısayolları nelerdir?', a: '"?" tuşuna basarak kısayol listesini görün. Tüm temel kısayollar:\n\nNavigasyon Kısayolları:\n- g + d: Dashboard (Kokpit) sayfasına git\n- g + t: Görevler sayfasına git\n- g + r: Raporlar sayfasına git\n- g + k: Kullanıcılar sayfasına git\n- g + h: Harita sayfasına git\n- g + s: Stok sayfasına git\n- g + i: IoT Cihazlar sayfasına git\n- g + m: Mesajlar sayfasına git\n\nİşlem Kısayolları:\n- n: Yeni oluşturma (bulunduğunuz sayfaya göre görev, rapor vb.)\n- /: Arama çubuğuna odaklan\n- Esc: Açık pencere veya paneli kapat\n- Ctrl + Enter: Formu gönder veya mesaj gönder\n\nBu kısayolları kullanarak fare kullanmadan hızlıca platformda gezinebilirsiniz.' },
 { q: 'Platformu verimli kullanma ipuçları', a: 'Deneyiminizi geliştirmek için şu ipuçlarını uygulayın:\n\n- Dashboard\'unuzu özelleştirin: En sık baktığınız verileri widget olarak dashboard\'a ekleyin\n- Filtreleri kaydedin: Sık kullandığınız filtre kombinasyonlarını kaydederek tek tıkla ulaşın\n- Kısayolları öğrenin: Klavye kısayolları ile işlemlerinizi çok daha hızlı yapabilirsiniz\n- OperIQ\'yu kullanın: Karmaşık sorular için yapay zeka asistanına doğal dilde soru sorun\n- Bildirimleri ayarlayın: Gereksiz bildirimleri kapatarak dikkat dağınıklığını azaltın\n- Mobil uygulamayı kurun: Sahada çalışırken mobil uygulama ile görev tamamlayın ve rapor gönderin\n- Düzenli veri girişi: KPI değerleri ve stok hareketlerini güncel tutun - otomasyon kuralları doğru veriye ihtiyaç duyar' },
 { q: 'Tarayıcı uyumluluğu ve öneriler', a: 'ActLedger şu tarayıcılarda en iyi performansı sunar:\n\n- Google Chrome (önerilen) - en son sürüm\n- Mozilla Firefox - en son sürüm\n- Microsoft Edge - en son sürüm\n- Safari (macOS) - en son sürüm\n\nEn iyi deneyim için:\n- Tarayıcınızı her zaman güncel tutun\n- JavaScript\'in aktif olduğundan emin olun\n- Pop-up engelleyicinin ActLedger adresini beyaz listeye aldığından emin olun\n- Minimum 1280x720 ekran çözünürlüğü önerilir\n- Stabil internet bağlantısı (en az 2 Mbps) gereklidir' },
 { q: 'Yardım ve destek alma', a: 'Sorun yaşadığınızda veya yardıma ihtiyaç duyduğunuzda şu kaynakları kullanın:\n\n- Bu Kılavuz: Sol menüdeki "Kullanım Kılavuzu" sayfası (şu an buradasınız)\n- OperIQ Asistan: Sağ alttaki sohbet balonuna tıklayarak AI asistana sorun\n- Destek Talebi: Profil menüsündeki "Destek" bölümünden destek talebi oluşturun\n- E-posta Destek: Teknik sorunlar için destek ekibine e-posta gönderin\n\nDestek talebi oluştururken şu bilgileri eklemeniz çözüm süresini kısaltır:\n- Sorunun ne olduğunu ve ne zaman başladığını açıklayın\n- Hangi sayfada veya modüldeki olduğunu belirtin\n- Ekran görüntüsü ekleyin (mümkünse)\n- Hangi tarayıcı ve cihazı kullandığınızı belirtin' },
 ],
 },
 {
 icon: HelpCircle, title: 'Sık Sorulan Sorular (SSS)',
 items: [
 { q: 'Şifresini unutan kullanıcıya nasıl yardımcı olunur?', a: 'Yönetici (Müdür seviyesi ve üstü) kullanıcının profilinden "Şifre Sıfırla" butonuna basarak yeni geçici şifre üretebilir. Geçici şifre kullanıcıya iletilir ve ilk girişte değiştirilmesi gerekir.\n\nNot: Güvenlik nedeniyle mevcut şifreleri göremezsiniz - sadece yeni geçici şifre üretebilirsiniz.' },
 { q: 'Veri kaybı yaşanır mı? Yedekleme nasıl çalışır?', a: 'ActLedger otomatik yedekleme sistemi ile verileriniz güvendedir:\n\n- Veritabanı yedeklemesi: Günlük otomatik yedekleme yapılır\n- Dosya yedeklemesi: Yüklenen tüm dosyalar redundant olarak saklanır\n- Veri tutma süresi: Silinen veriler 30 gün boyunca geri alınabilir\n\nPlatformda yaptığınız tüm değişiklikler anlık olarak kaydedilir. İnternet bağlantısı koptuğunda mobil uygulamadaki veriler cihazda saklanır ve bağlantı geri geldiğinde otomatik senkronize edilir. Veri kaybı riski minimumdur.' },
 { q: 'Platformda hata veya yavaşlık yaşıyorum, ne yapmalıyım?', a: 'Platform performans sorunu yaşadığınızda şu adımları deneyin:\n\n1. Tarayıcı Önbelleği: Ctrl+Shift+Delete ile tarayıcı önbelleğini temizleyin\n2. Sayfayı Yenileyin: F5 veya Ctrl+R ile sayfayı yeniden yükleyin\n3. Farklı Tarayıcı: Başka bir tarayıcıda deneyin (Chrome önerilir)\n4. İnternet Bağlantısı: Bağlantı hızınızı kontrol edin (en az 2 Mbps)\n5. Eklentiler: Tarayıcı eklentilerini geçici olarak devre dışı bırakın\n6. Cihaz: Bilgisayarınızı yeniden başlatın\n\nSorun devam ediyorsa destek talebi oluşturun ve şu bilgileri ekleyin: hangi sayfada sorun yaşandığını, ne zaman başladığını, tarayıcı adını ve sürümünü.' },
 { q: 'Birden fazla departmanda görev atayabilir miyim?', a: 'Evet, görev oluşturulurken birden fazla departmandan kişi seçebilirsiniz. Görev birden fazla kişiye atanabilir ve her atanan kişi görevi kendi görev listesinde görür.\n\nDepartmanlar arası görev ataması için yeterli yetki seviyesine sahip olmanız gerekir. Normalde bir kullanıcı yalnızca kendi departmanındaki kişilere görev atayabilir. Birden fazla departmana atama yapmak için en az Müdür (Seviye 6) veya üstü rolüne ihtiyacınız vardır.\n\nGörev detayında "Atananlar" bölümünden kişileri ekleyebilir veya çıkarabilirsiniz.' },
 { q: 'OperIQ analizi ne kadar günceldir?', a: 'OperIQ, platform verilerinizi gerçek zamanlı olarak kullanır. Analiz istediğinizde o anki mevcut tüm verileri dikkate alır. IoT verileri, görev durumları, stok seviyeleri ve raporlar dahil tüm veriler anlık olarak OperIQ\'nun bilgi havuzuna yansır.\n\nOperIQ\'nun sunabileceği analiz derinliği, platformda ne kadar veri bulunduğuna bağlıdır. Platform ne kadar uzun süredir kullanılıyorsa ve ne kadar çok veri girildiyse, OperIQ o kadar detaylı ve isabetli analizler üretir.\n\nGünlük fotoğraf analiz limiti mobil uygulamada 5 adet ile sınırlıdır. Platform üzerinde ise metin bazlı sorularda limit yoktur.' },
 { q: 'Excel veya CSV ile toplu veri yükleme başarısız oluyor, ne yapmalıyım?', a: 'Toplu veri yüklemede sorun yaşadığınızda şu kontrolleri yapın:\n\n- Dosya Formatı: Dosyanızın .xlsx veya .csv formatında olduğundan emin olun (.xls desteklenmez)\n- Sütun Başlıkları: Şablondaki sütun başlıklarını değiştirmeyin\n- Boş Satırlar: Veri arasında boş satır bırakmayın\n- Özel Karakterler: Veri içerisinde beklenmedik özel karakterler olmadığından emin olun\n- Dosya Boyutu: Maksimum dosya boyutu 10 MB\'dir\n- Satır Limiti: Tek seferde maksimum 5000 satır yüklenebilir\n\nÖnizleme ekranında hatalı satırlar kırmızı ile işaretlenir ve hata açıklaması görüntülenir. Hatalı satırları düzelttikten sonra tekrar deneyin. OperIQ sütun eşleştirme aşamasında otomatik düzeltme önerileri de sunar.' },
 ],
 },
]

const MOBILE_GUIDE_TR: Section[] = [
 {
 icon: Smartphone, title: 'Giriş & Başlangıç',
 items: [
 { q: 'Mobil giriş nasıl yapılır?', a: 'Admin tarafından verilen giriş kodu (ACT-XXXXXX) ve geçici şifre ile giriş yapın. Giriş ekranında şu adımları izleyin:\n\n1. "Giriş Kodu" alanına ACT-XXXXXX formatındaki kodunuzu girin\n2. "Şifre" alanına geçici şifrenizi girin\n3. "Giriş Yap" butonuna basın\n4. İlk girişte sistem sizden yeni şifre belirlemenizi isteyecektir\n5. Yeni şifrenizi girin ve onaylayın\n\nŞifreniz en az 8 karakter uzunluğunda olmalı, büyük harf, küçük harf ve rakam içermelidir. Giriş kodunuzu ve şifrenizi başkası ile paylaşmayın. Şifrenizi unutursanız yöneticinizden yeni geçici şifre talep edin.' },
 { q: 'Uygulama ana sayfasında ne var?', a: 'Mobil uygulama basit ve kullanımı kolay bir arayüze sahiptir. Ana bileşenler:\n\nAlt Menü (4 sekme):\n- Görevler: Size atanan tüm görevler ve durumları\n- Formlar: Doldurmanız gereken saha formları\n- OperIQ Asistan: Yapay zeka sohbet ekranı\n- Profil: Kişisel bilgiler, ayarlar ve çıkış\n\nÜst Bar:\n- Senkronizasyon Butonu: Verileri sunucu ile eşitleme (yeşil = güncel, turuncu = bekleyen veri var)\n- Bildirim Zili: Yeni bildirimler ve uyarılar (kırmızı nokta = okunmamış bildirim var)\n- Şirket Logosu: Ana sayfaya dönüş\n\nAna ekranda ayrıca günün özeti görüntülenir: bekleyen görev sayısı, bugün tamamlanan görevler ve önemli bildirimler.' },
 { q: 'Uygulamayı ana ekrana ekleme (PWA)', a: 'ActLedger mobil uygulaması Progressive Web App (PWA) olarak çalışır. Uygulama marketinden indirmeye gerek yoktur. Ana ekrana eklemek için:\n\niPhone / Safari:\n1. ActLedger mobil adresini Safari\'de açın\n2. Alt menüdeki paylaşım (kare + ok) ikonuna tıklayın\n3. "Ana Ekrana Ekle" seçeneğini seçin\n4. "Ekle" butonuna basın\n\nAndroid / Chrome:\n1. ActLedger mobil adresini Chrome\'da açın\n2. Üst menüdeki üç nokta ikonuna tıklayın\n3. "Ana ekrana ekle" seçeneğini seçin\n4. "Ekle" butonuna basın\n\nAna ekrana eklendikten sonra uygulama diğer uygulamalar gibi ikon ile görünür ve tam ekran modunda çalışır.' },
 { q: 'Bildirim izinlerini ayarlama', a: 'Mobil uygulamadan anlık bildirimler alabilmek için cihazınızın bildirim iznini vermeniz gerekir. İlk girişte uygulama sizden bildirim izni isteyecektir.\n\nİzni vermek için:\n- iPhone: "İzin Ver" butonuna basın. Daha sonra Ayarlar > Bildirimler > ActLedger yolundan ayarlayabilirsiniz.\n- Android: "İzin Ver" butonuna basın. Daha sonra Ayarlar > Uygulamalar > ActLedger > Bildirimler yolundan ayarlayabilirsiniz.\n\nBildirim izni verildikten sonra şu durumlarda anlık bildirim alırsınız:\n- Size yeni görev atandığında\n- Görev durumu değiştiğinde\n- Yeni mesaj geldiğinde\n- Onay bekleyen iş akışı adımınız olduğunda' },
 ],
 },
 {
 icon: ClipboardList, title: 'Görevler',
 items: [
 { q: 'Görevlerimi nasıl görürüm?', a: '"Görevler" sekmesinde size atanan tüm aktif görevler listelenir. Görev listesinde her kart üzerinde şu bilgiler görüntülenir:\n\n- Görev Başlığı\n- Öncelik seviyesi (renk kodu ile)\n- Teslim tarihi\n- Mevcut durum (Beklemede, Devam Ediyor, Tamamlandı)\n- Checklist ilerleme yüzdesi\n\nListeyi filtrelemek için üst kısımdaki filtre butonlarını kullanın:\n- Tümü: Tüm görevleriniz\n- Aktif: Beklemede ve devam eden görevler\n- Tamamlandı: Tamamlanmış görevler\n- Geciken: Teslim tarihi geçmiş görevler (kırmızı ile işaretlenir)\n\nGörevler varsayılan olarak öncelik sırasına göre sıralanır. Teslim tarihine göre sıralamak için sıralama butonuna basın.' },
 { q: 'Görev nasıl tamamlanır?', a: 'Görev tamamlama süreci adım adım şu şekildedir:\n\n1. Görev listesinden göreve tıklayın - detay sayfası açılır\n2. Görevin açıklama ve talimatlarını okuyun\n3. Checklist maddeleri varsa her tamamlanan adımı işaretleyin\n4. Gerekirse yorum veya not ekleyin\n5. Fotoğraf eklemeniz gerekiyorsa kamera ikonuyla çekin veya galeriden seçin\n6. Üst kısımdaki durum alanına tıklayın\n7. "Tamamlandı" seçeneğini seçin\n8. Onay ekranında "Onayla" butonuna basın\n\nGörev tamamlandığında görev sahibine (oluşturana) otomatik bildirim gönderilir. Tamamlanan görevler "Tamamlandı" filtresinde görüntülenir. Gerekirse yönetici görevi tekrar "Devam Ediyor" durumuna döndürebilir.' },
 { q: 'Göreve yanıt ve yorum ekleme', a: 'Görev detay sayfasının alt kısmında yorum alanı bulunur. Burada görev hakkında bilgi paylaşabilir, soru sorabilir veya ilerleme bildirimi yapabilirsiniz.\n\nYorum eklemek için:\n1. Görev detay sayfasını açın\n2. "Yorum Ekle" alanına tıklayın\n3. Mesajınızı yazın\n4. Gerekirse ataç ikonuyla dosya veya fotoğraf ekleyin\n5. "Gönder" butonuna basın\n\nYorumlarınız görev geçmişinde kronolojik sıraya ile görüntülenir. Tüm ilgili kişiler (görev sahibi ve diğer atanan kişiler) yorumunuzu bildirim olarak alır. Bu sayede görev hakkındaki tüm iletişim tek bir yerde toplanmış olur.' },
 { q: 'Göreve fotoğraf ekleme', a: 'Sahada çalışırken görevlere fotoğraf eklemek oldukça kolaydır:\n\n1. Görev detay sayfasını açın\n2. "Fotoğraf Ekle" veya kamera ikonuna tıklayın\n3. Seçenekler görüntülenir:\n - Kamera: Telefonunuzun kamerasını açarak anlık fotoğraf çekin\n - Galeri: Telefonunuzda kayıtlı bir fotoğrafı seçin\n4. Fotoğraf eklendikten sonra opsiyonel açıklama yazabilirsiniz\n5. "Kaydet" ile fotoğrafı göreve ekleyin\n\nEklenen fotoğraflar görev detayında galeri olarak görüntülenir. Fotoğraflar otomatik olarak sunucuya yüklenir - internet bağlantısı yoksa çevrimdışı olarak saklanır ve bağlantı geri geldiğinde otomatik yüklenir.' },
 ],
 },
 {
 icon: Workflow, title: 'İş Siparişleri',
 items: [
 { q: 'Mobilde İş Siparişlerine nasıl erişilir?', a: 'Mobil uygulamada alt menüden "İş Siparişleri" sekmesine dokunarak erişebilirsiniz. Ana ekranda tüm iş siparişleriniz kart bazlı liste halinde görüntülenir.\n\nHer kartta şu bilgiler yer alır:\n- Sipariş numarası (WO-2026-XXXX)\n- Başlık ve hedef departman\n- Öncelik seviyesi (renk kodu ile)\n- Mevcut durum\n- Son tarih\n- İş kalemleri ilerleme yüzdesi\n\nÜst kısımdaki hızlı filtre sekmeleri ile siparişlerinizi filtreleyebilirsiniz: Tümü, Taslak, Onay Bekliyor, Devam Ediyor, Kapandı. Ayrıca arama çubuğu ile sipariş numarası veya başlığa göre arama yapabilirsiniz.' },
 { q: 'Mobilde yeni İş Siparişi nasıl oluşturulur?', a: 'Sağ üstteki "Yeni" butonuna dokunarak yeni iş siparişi oluşturabilirsiniz. Form adımları:\n\n1. Başlık: Siparişi kısa ve net tanımlayan bir başlık girin\n2. Açıklama: İşin detaylarını ve beklentilerinizi yazın\n3. Hedef Departman: Listeden işi yapacak departmanı seçin\n4. Öncelik: Düşük, Normal, Yüksek veya Kritik seçin\n5. Son Tarih: Tarih seçiciden son tarihi belirleyin\n6. Tahmini Süre: Beklenen çalışma süresini saat cinsinden girin\n7. İş Kalemleri: Alt adımlar ekleyerek yapılacak işleri listeleyin\n\n"Taslak Kaydet" ile taslak olarak saklayabilir veya "Gönder" ile doğrudan müdür onayına gönderebilirsiniz.\n\nNot: İş siparişi açabilmek için Süpervizör veya üstü rol seviyesine sahip olmanız gerekir.' },
 { q: 'İş Siparişi detayında neler var?', a: 'Listeden bir siparişe dokunarak detay ekranını açabilirsiniz. Detay ekranında sekmeler halinde bilgiler sunulur:\n\nBilgi Kartı:\n- Sipariş numarası, başlık, açıklama\n- Talep eden ve hedef departman\n- Öncelik, durum, son tarih\n- Tahmini ve gerçekleşen süre/maliyet\n\nİş Kalemleri:\n- Alt adımları listeler\n- Tamamlanan kalemleri tik atarak işaretleyebilirsiniz\n- İlerleme yüzdesi otomatik güncellenir\n\nYorumlar:\n- Karşı departmanla iletişim kurabilirsiniz\n- Mesaj yazıp "Gönder" ile paylaşın\n\nEkler:\n- Dosya ve fotoğraf yükleyebilirsiniz\n- "Talep" ve "Tamamlama" etiketleri ile ayrılır\n\nMalzemeler:\n- Kullanılan malzemeleri ekleyebilirsiniz\n\nGeçmiş:\n- Tüm durum değişiklikleri kronolojik olarak listelenir' },
 { q: 'Mobilde onay ve kabul işlemleri nasıl yapılır?', a: 'Siparişin durumuna göre ekranın altında sabit aksiyon butonları görüntülenir:\n\nMüdür Onayı Bekliyor (talep eden departman müdürüyseniz):\n- "Onayla" - siparişi hedef departmana iletir\n- "Reddet" - siparişi reddeder (sebep zorunlu)\n- "Revize İste" - açan kişiye geri gönderir\n\nKarşı Taraf Bekliyor (hedef departman müdürü/süpervizörüyseniz):\n- "Kabul Et" - işi başlatır\n- "Reddet" - siparişi reddeder\n\nDevam Ediyor (hedef departmandaysanız):\n- "Tamamlandı" - işin bittiğini bildirir\n\nAçan Onayı Bekliyor (talep eden müdürseniz):\n- "Onayla ve Kapat" - siparişi kapatır\n- "Revize İste" - işi geri gönderir\n\nHer işlemde onay ekranı çıkar. Gerekirse not ekleyerek onaylayabilirsiniz.' },
 { q: 'İş Siparişi bildirimleri nasıl gelir?', a: 'İş siparişleriyle ilgili tüm önemli olaylarda push bildirim alırsınız:\n\n- Size yeni iş siparişi atandığında\n- Departmanınıza iş siparişi geldiğinde\n- Sipariş onaylandığında veya reddedildiğinde\n- Karşı taraf kabul ettiğinde veya reddettiğinde\n- İş tamamlandığında\n- Son tarih yaklaştığında veya aşıldığında\n- Yorum eklendiğinde\n\nBildirimlere dokunarak doğrudan ilgili siparişin detay ekranına gidebilirsiniz.\n\nBildirim tercihlerini "Profil > Ayarlar" sayfasından kişiselleştirebilirsiniz. Yorum bildirimleri varsayılan olarak kapalıdır, isterseniz açabilirsiniz.' },
 { q: 'Mobilde maliyet ve malzeme takibi nasıl yapılır?', a: 'Sipariş detay ekranındaki "Malzemeler" sekmesinden kullanılan malzemeleri ekleyebilirsiniz:\n\nMalzeme Ekleme:\n1. "Malzeme Ekle" butonuna dokunun\n2. Malzeme adını girin\n3. Miktar ve birim seçin (adet, kg, metre vb.)\n4. Birim maliyeti girin\n5. "Kaydet" ile ekleyin\n\nMaliyet Girişi:\n- İş tamamlandığında "Gerçekleşen Maliyet" ve "Gerçekleşen Süre" alanlarını doldurun\n- Tahmini ve gerçekleşen değerler bilgi kartında karşılaştırmalı olarak gösterilir\n\nMalzeme listesi ve maliyet bilgileri platform tarafında da anlık olarak görüntülenir. Bu sayede yöneticiler saha harcamalarını gerçek zamanlı takip edebilir.' },
 ],
 },
 {
 icon: FileText, title: 'Formlar & Raporlar',
 items: [
 { q: 'Formlar sekmesinde neler görünür?', a: '"Formlar" sekmesinde iki tür içerik görünür:\n\n1. Atanan Raporlar (üst kısım, turuncu arka plan):\n- Platformdaki yöneticiniz tarafından size iletilen raporlardır\n- "Rapor: ..." başlığı ile görünür\n- Öncelik seviyesi (Düşük/Orta/Yüksek/Kritik) ve atayan kişi bilgisi gösterilir\n- Tıklayarak raporu açın ve işlem yapın\n\n2. Form Şablonları (alt kısım):\n- Doldurmanız gereken standart saha formlarıdır\n- Alan sayısı ve departman bilgisi gösterilir\n- Tıklayarak formu doldurun\n\nÖncelikle atanan raporlara işlem yapın - bunlar yöneticiniz tarafından sizden beklenen görevlerdir.' },
 { q: 'Atanan rapora nasıl işlem yapılır?', a: 'Formlar sekmesinde "Rapor: ..." başlıklı bir karta tıklayın. Rapor detay sayfası açılır:\n\n1. Raporun başlığını, açıklamasını ve öncelik seviyesini okuyun\n2. Durum seçimi yapın:\n - Tamamlandı: Rapordaki konu başarıyla çözüldü\n - Sorun Var: Rapordaki konuda sorun tespit edildi\n3. Not/Açıklama alanına saha notunuzu yazın (ne yaptınız, ne gördünüz)\n4. "Gönder" butonuna basın\n\nGönderdiğinizde:\n- GPS konumunuz otomatik kaydedilir\n- Rapor sahibine anlık bildirim gider\n- OperIQ yapay zeka analizi otomatik başlatılır\n- Platform kullanıcıları rapor durumunu anlık görür\n\nNotunuz rapor detayında "Saha Notu" olarak görüntülenir.' },
 { q: 'Form nasıl doldurulur?', a: '"Formlar" sekmesinden doldurmanız gereken formları görün. Form doldurma adımları:\n\n1. Form listesinden ilgili form şablonunu seçin\n2. Form alanları görüntülenir - her alanı sıraya ile doldurun\n3. Alan tipleri: metin, sayı, tarih, tekli/çoklu seçim, fotoğraf, konum\n4. Zorunlu alanlar yıldız (*) işareti ile belirtilmiştir\n5. Fotoğraf alanı varsa kamera veya galeriden seçim yapın\n6. Konum alanı varsa mevcut konumunuzu otomatik ekleyin\n7. Tüm alanları doldurduktan sonra "Gönder" butonuna basın\n8. Onay ekranında bilgileri kontrol edin ve "Onayla" ile gönderin\n\nGönderilen formlar yöneticinize bildirim olarak iletilir. Form geçmişinde daha önce doldurduğunuz formları görebilirsiniz.' },
 { q: 'Form taslağı kaydetme', a: 'Formu hemen tamamlayamıyorsanız taslak olarak kaydetme özelliğini kullanın:\n\n1. Formu kısmi olarak doldurun\n2. Sağ üstteki "Taslak Kaydet" butonuna basın\n3. Form "Taslaklarım" bölümünde görüntülenir\n4. Daha sonra taslağa tıklayarak kaldığınız yerden devam edin\n5. Tüm alanları doldurunca "Gönder" ile gönderin\n\nTaslaklar cihazınızda ve sunucuda saklanır. İnternet bağlantısı olmasa bile taslak kaydetme çalışır. Taslak formları düzenleyebilir veya silebilirsiniz.' },
 { q: 'Form geçmişi ve tekrar gönderme', a: 'Daha önce doldurduğunuz formları "Form Geçmişi" bölümünde görebilirsiniz. Geçmiş formlar şu bilgilerle listelenir:\n\n- Form adı ve tarihi\n- Durum: Gönderildi, İnceleniyor, Onaylandı, Reddedildi\n- Gönderilen veriler (salt okunur)\n\nBir formu tekrar doldurmak için geçmiş formun yanındaki "Tekrar Doldur" butonuna basın. Önceki yanıtlar ön-doldurulmuş olarak görüntülenir - değiştirmek istediğiniz alanları güncelleyip yeniden gönderin.\n\nReddedilen formlar için red nedeni görüntülenir. Gerekli düzeltmeleri yaparak formu tekrar gönderebilirsiniz.' },
 { q: 'Formda fotoğraf ve konum ekleme', a: 'Bazı form şablonlarında fotoğraf ve konum alanları zorunlu olabilir. Bu alanlar saha çalışmalarınızı belgelemek için kullanılır.\n\nFotoğraf Alanı:\n- Kamera ikonuna tıklayın\n- "Fotoğraf Çek" ile kamerayı açın veya "Galeriden Seç" ile mevcut bir fotoğrafı seçin\n- Birden fazla fotoğraf eklemeyi destekleyen alanlarda "+" butonu ile ek fotoğraf ekleyin\n- Her fotoğraf için opsiyonel açıklama yazabilirsiniz\n\nKonum Alanı:\n- "Konumumu Ekle" butonuna tıklayın\n- Cihazınız mevcut GPS konumunuzu alır\n- Konum adresi otomatik olarak görüntülenir\n- Konum izni vermiş olmanız gerekir' },
 ],
 },
 {
 icon: Zap, title: 'OperIQ Mobil Asistan',
 items: [
 { q: 'OperIQ\'ya nasıl soru sorarım?', a: 'Alt menüdeki OperIQ ikonuna tıklayın. Sohbet ekranı açılır ve yapay zeka asistanına doğal dilde soru sorabilirsiniz.\n\nOperIQ\'ya sorabileceğiniz örnek sorular:\n- "Bugün benim görevlerim nelerdir?"\n- "Departmanımdaki geciken görevler hangileri?"\n- "Stok durumu nasıl?"\n- "Bu makinenin bakım prosedürü nedir?"\n- "Son haftanın rapor özeti"\n\nOperIQ, şirketinize özel verileri kullanarak cevap verir. Türkçe veya İngilizce soru sorabilirsiniz. Kısa ve net sorular daha isabetli yanıtlar almanızı sağlar.\n\nSohbet geçmişiniz saklanır - önceki konuşmalarınızı kaydırarak görebilirsiniz. "Yeni Sohbet" butonu ile temiz bir sohbet başlatabilirsiniz.' },
 { q: 'Fotoğraf analizi nasıl yapılır?', a: 'OperIQ sohbet ekranında görsel analiz özelliği ile sahadaki durumları yapay zeka ile değerlendirebilirsiniz:\n\n1. Sohbet ekranında kamera ikonuna tıklayın\n2. "Fotoğraf Çek" ile kameranızı açın veya "Galeriden Seç" ile mevcut fotoğraf seçin\n3. Fotoğrafın ne hakkında analiz istediğinizi yazın (ör: "Bu makine panosu normal mi?", "Bu hasarı değerlendir")\n4. "Gönder" butonuna basın\n5. OperIQ fotoğrafı analiz ederek bulguları metin olarak raporlar\n\nFotoğraf analizi şu durumlarda faydalıdır:\n- Ekipman veya makine durumu değerlendirme\n- Hasar veya arıza tespit\n- Güvenlik kontrolü\n- Stok sayımı doğrulama\n\nGünlük fotoğraf analiz limiti 5 adet ile sınırlıdır. Limit gece yarısı sıfırlanır.' },
 { q: 'Sesli komut kullanma', a: 'OperIQ sohbet ekranında mikrofon ikonuyla sesli mesaj gönderebilirsiniz:\n\n1. Mikrofon ikonuna tıklayın ve basın\n2. Sorunuzu veya komutunuzu konuşun\n3. Bırakın - sesiniz metne dönüştürülür\n4. Dönüştürülen metni kontrol edin\n5. "Gönder" ile gönderin\n\nSesli komut özellikle elleriniz meşgulken (saha çalışırken, ekipman kontrol ederken) kullanışlıdır. Türkçe ve İngilizce ses tanıma desteklenir. Gürültülü ortamlarda net konuşmaya dikkat edin.' },
 { q: 'OperIQ ile hızlı işlem yapma', a: 'OperIQ sadece soru cevaplamakla kalmaz, bazı işlemleri de sizin adınıza yapabilir:\n\n- "Yeni görev oluştur: Depo raflarını kontrol et" - görev oluşturma\n- "Bugünkü görevlerimi özetle" - görev özeti alma\n- "Sıcaklık sensörü son 24 saat grafiği" - veri sorgulama\n- "Bu haftanın raporlarını listele" - rapor sorgulama\n\nOperIQ işlem yapmadan önce sizden onay ister. Örneğin görev oluşturma komutunda önceliği, atamayı ve teslim tarihini sorar. Onayladığınızda işlem tamamlanır.\n\nBu özellik ile platform arayüzüne geçmeden hızlıca işlemler yapabilirsiniz.' },
 ],
 },
 {
 icon: Map, title: 'Konum & Senkronizasyon',
 items: [
 { q: 'Konum paylaşımı nasıl çalışır?', a: 'Mobil uygulamada konum paylaşımı şu şekilde çalışır:\n\n1. İlk kullanımda uygulama konum izni ister - "Her Zaman İzin Ver" seçeneğini seçin\n2. Konum izni verildikten sonra uygulamanız 60 saniyede bir konumunuzu platforma gönderir\n3. Konumunuz canlı harita üzerinde gerçek zamanlı olarak görüntülenir\n4. Profilinizde mevcut konumunuzu ve son güncelleme zamanını görebilirsiniz\n\nKonum paylaşımı hakkında önemli bilgiler:\n- Konum verisi sadece çalışma saatlerinde paylaşılır\n- GPS doğruluğu içeride 10-20 metre, dışarıda 3-5 metre civarındadır\n- Batarya tüketimini minimize etmek için optimize edilmiştir\n- Konum paylaşımını profil ayarlarından geçici olarak durdurabilirsiniz\n- Yöneticiniz konum geçmişinizi harita üzerinde rota olarak görebilir' },
 { q: 'Çevrimdışı çalışma nasıl olur?', a: 'İnternet bağlantısı kesildiğinde mobil uygulama çevrimdışı modda çalışmaya devam eder:\n\nÇevrimdışı yapılabilecekler:\n- Görev listesini görüntüleme (son senkronizasyondaki hali)\n- Görev durumu güncelleme\n- Checklist maddeleri işaretleme\n- Form doldurma ve taslak kaydetme\n- Yorum ve not ekleme\n- Fotoğraf çekme ve göreve ekleme\n\nTüm bu işlemler cihazınızda yerel olarak saklanır. İnternet bağlantısı geri geldiğinde:\n1. Üst bardaki senkronizasyon butonu turuncu yanıp söner\n2. Otomatik senkronizasyon başlar (veya butona basarak manuel başlatın)\n3. Bekleyen tüm veriler sunucuya yüklenir\n4. Sunucudaki yeni veriler cihazınıza indirilir\n5. Senkronizasyon tamamlanınca buton yeşile döner\n\nÇevrimdışı modda yapılan işlemlerde tarih ve saat bilgisi cihaz saatine göre kaydedilir.' },
 { q: 'Batarya ve veri kullanımı', a: 'Mobil uygulamanın batarya ve veri kullanımını optimize etmek için:\n\nBatarya Tasarrufu:\n- Konum güncelleme sıklığı otomatik olarak optimize edilir\n- Arkaplanda minimum batarya tüketimi (günlük ~%3-5)\n- Düşük batarya modunda konum güncelleme sıklığı azalır\n\nMobil Veri Kullanımı:\n- Uygulama aylık yaklaşık 50-100 MB veri kullanır (fotoğrafsız)\n- Fotoğraflar WiFi bağlantısı tercih edilerek yüklenir\n- Ayarlardan "Sadece WiFi ile Senkronize Et" seçeneğini açabilirsiniz\n- Çevrimdışı modda veri kullanımı sıfırdır\n\nBatarya veya veri kullanımında anormal artış fark ederseniz uygulamayı kapatıp tekrar açın veya cihazınızı yeniden başlatın.' },
 { q: 'Senkronizasyon sorunlarını giderme', a: 'Senkronizasyon sorunları yaşadığınızda şu adımları deneyin:\n\n1. İnternet Bağlantısı: WiFi veya mobil veri bağlantınızın aktif olduğundan emin olun\n2. Manuel Senkronizasyon: Üst bardaki senkronizasyon butonuna basın\n3. Uygulamayı Yeniden Başlatın: Uygulamayı tamamen kapatıp tekrar açın\n4. Cihaz Depolama: Cihazınızda yeterli boş alan olduğundan emin olun (en az 100 MB)\n5. Uygulama Güncelleme: Tarayıcıdaki önbelleği temizleyip sayfayı yeniden yükleyin\n\nSenkronizasyon durumu:\n- Yeşil: Tüm veriler güncel\n- Turuncu: Bekleyen veriler var, senkronizasyon devam ediyor\n- Kırmızı: Senkronizasyon hatası - üstteki adımları deneyin\n\nSorun devam ediyorsa yöneticinize veya teknik desteğe bildirin.' },
 ],
 },
 {
 icon: Bell, title: 'Mobil Bildirimler',
 items: [
 { q: 'Push bildirimler nasıl çalışır?', a: 'Mobil uygulamada push bildirimler ile önemli olaylardan anında haberdar olursunuz.\n\nBildirim alacağınız durumlar:\n- Size yeni görev atandığında\n- Görev durumu değiştiğinde\n- Görev yorumu eklendiğinde\n- Yeni mesaj geldiğinde\n- İş akışında onay beklediğinde\n- IoT alarm tetiklendiğinde (yetkiniz varsa)\n\nBildirimlere tıklayarak doğrudan ilgili sayfaya yönlendirilirsiniz. Örneğin görev bildirimine tıklamak görev detay sayfasını açar.\n\nBildirim almıyorsanız:\n1. Cihaz ayarlarından bildirim izninin verildiğinden emin olun\n2. "Rahatsız Etmeyin" modunun kapalı olduğundan emin olun\n3. Uygulamanın arka planda çalışmasına izin verildiğinden emin olun' },
 { q: 'Bildirim sesini ve titreşimini ayarlama', a: 'Bildirim ses ve titreşim ayarlarını cihazınızın ayarlarından yapabilirsiniz:\n\niPhone:\n1. Ayarlar > Bildirimler > ActLedger\n2. Ses, Rozet ve Banner ayarlarını yapın\n3. Kilit ekranında görünüp görünmeyeceğini seçin\n\nAndroid:\n1. Ayarlar > Uygulamalar > ActLedger > Bildirimler\n2. Bildirim kategorilerini ayrı ayrı ayarlayın\n3. Ses, titreşim ve öncelik seçeneklerini belirleyin\n\nGece saatlerinde rahatsız edilmemek için cihazınızın "Rahatsız Etmeyin" zamanlama özelliğini kullanabilirsiniz. Bu sayede mesai dışında bildirim almayı durdurabilirsiniz.' },
 ],
 },
 {
 icon: Settings, title: 'Profil & Ayarlar',
 items: [
 { q: 'Profil bilgilerini görüntüleme', a: '"Profil" sekmesinde şu bilgilerinizi görebilirsiniz:\n\n- Ad ve Soyad\n- E-posta adresi\n- Departman ve Rol\n- Giriş kodu (ACT-XXXXXX)\n- Mevcut konum (konum paylaşımı aktifse)\n- Son senkronizasyon zamanı\n- Uygulama sürümü\n\nProfil fotoğrafınızı değiştirmek için fotoğraf alanına tıklayın ve kamera veya galeriden seçim yapın.' },
 { q: 'Şifre değiştirme', a: 'Şifrenizi değiştirmek için:\n\n1. "Profil" sekmesine gidin\n2. "Şifre Değiştir" butonuna basın\n3. Mevcut şifrenizi girin\n4. Yeni şifrenizi girin (en az 8 karakter, büyük harf, küçük harf, rakam)\n5. Yeni şifrenizi tekrar girerek onaylayın\n6. "Kaydet" butonuna basın\n\nŞifre başarıyla değiştirildiğinde onay mesajı görüntülenir. Bir sonraki girişte yeni şifrenizi kullanın. Mevcut oturumunuz devam eder.\n\nŞifrenizi unutursanız yöneticinizden geçici şifre talep edin.' },
 { q: 'Dil ve bildirim tercihleri', a: 'Profil ayarlarından dil ve bildirim tercihlerinizi yapılandırabilirsiniz:\n\nDil Seçimi:\n- Türkçe veya İngilizce arasında seçim yapın\n- Dil değişikliği anında uygulanır\n\nBildirim Tercihleri:\n- Görev bildirimleri: Açık/Kapalı\n- Mesaj bildirimleri: Açık/Kapalı\n- IoT alarm bildirimleri: Açık/Kapalı\n- Sistem duyuruları: Açık/Kapalı\n\nBu ayarlar sadece mobil bildirimler içindir. Platform (web) bildirimleri ayrı olarak profil sayfasından ayarlanır.' },
 { q: 'Güvenli çıkış yapma', a: 'Uygulamadan güvenli çıkış yapmak için:\n\n1. "Profil" sekmesine gidin\n2. Sayfanın altındaki "Çıkış Yap" butonuna basın\n3. Onay ekranında "Evet, Çıkış Yap" butonuna basın\n\nÇıkış yapıldığında:\n- Oturumunuz sonlandırılır\n- Yerel veriler silinir\n- Konum paylaşımı durur\n- Giriş ekranına yönlendirilirsiniz\n\nÖnemli: Paylaşılan veya başkasının cihazından giriş yaptıysanız işleriniz bittiğinde mutlaka çıkış yapın. Çıkış yapmadan cihazı başkasına vermeyin.' },
 ],
 },
]

// ── Full English translations (imported from separate file) ──
import { PLATFORM_GUIDE_EN, MOBILE_GUIDE_EN } from './UserGuide.en'

export default function UserGuide() {
 const { lang } = useLanguage()
 const navigate = useNavigate()
 const [tab, setTab] = useState<'platform' | 'mobile'>('platform')
 const [openSections, setOpenSections] = useState<Set<number>>(new Set([0]))
 const [navTarget, setNavTarget] = useState<string | null>(null)

 const tr = lang === 'tr'
 const sections = tab === 'platform'
  ? (tr ? PLATFORM_GUIDE_TR : PLATFORM_GUIDE_EN)
  : (tr ? MOBILE_GUIDE_TR : MOBILE_GUIDE_EN)

 const toggleSection = (idx: number) => {
 setOpenSections(prev => {
 const next = new Set(prev)
 next.has(idx) ? next.delete(idx) : next.add(idx)
 return next
 })
 }

 return (
 <div className="space-y-5">
 <style>{`@keyframes bounceRight { 0%, 100% { transform: translateX(0); } 50% { transform: translateX(6px); } } .animate-bounce-right { animation: bounceRight 0.6s ease-in-out 3; }`}</style>
 <div className="flex items-center justify-between">
 <div>
 <h2 className="text-[18px] font-bold text-zinc-900 tracking-tight flex items-center gap-2">
 <BookOpen size={20} className="text-cyan-600" />
 {lang === 'tr' ? 'Kullanım Kılavuzu' : 'User Guide'}
 </h2>
 <p className="text-[12px] text-zinc-400 mt-0.5">
 {lang === 'tr' ? 'ActLedger platformunu ve mobil uygulamayı nasıl kullanacağınızı öğrenin' : 'Learn how to use ActLedger platform and mobile app'}
 </p>
 </div>
 </div>

 {/* Tab switch */}
 <div className="flex gap-2">
 <button type="button" onClick={() => { setTab('platform'); setOpenSections(new Set([0])) }}
 className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-[13px] font-bold transition-all ${tab === 'platform' ? 'bg-cyan-50 text-cyan-700 border-2 border-cyan-200' : 'bg-white border-2 border-zinc-200 text-zinc-600 hover:border-zinc-300'}`}>
 <Monitor size={16} /> {lang === 'tr' ? 'Platform Kılavuzu' : 'Platform Guide'}
 </button>
 <button type="button" onClick={() => { setTab('mobile'); setOpenSections(new Set([0])) }}
 className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-[13px] font-bold transition-all ${tab === 'mobile' ? 'bg-violet-50 text-violet-700 border-2 border-violet-200' : 'bg-white border-2 border-zinc-200 text-zinc-600 hover:border-zinc-300'}`}>
 <Smartphone size={16} /> {lang === 'tr' ? 'Mobil Kılavuz' : 'Mobile Guide'}
 </button>
 </div>

 {/* Sections */}
 <div className="space-y-2">
 {sections.map((section, idx) => {
 const isOpen = openSections.has(idx)
 return (
 <div key={idx} className="card overflow-hidden">
 <button type="button" onClick={() => toggleSection(idx)}
 className="w-full flex items-center gap-3 px-5 py-4 text-left hover:bg-zinc-50 transition-colors">
 <div className={`w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0 ${tab === 'platform' ? 'bg-cyan-100' : 'bg-violet-100'}`}>
 <section.icon size={16} className={tab === 'platform' ? 'text-cyan-600' : 'text-violet-600'} />
 </div>
 <span className="text-[14px] font-bold text-zinc-800 flex-1">{section.title}</span>
 <span className="text-[11px] text-zinc-400 mr-2">{section.items.length} {lang === 'tr' ? 'konu' : 'topics'}</span>
 {isOpen ? <ChevronDown size={16} className="text-zinc-400" /> : <ChevronRight size={16} className="text-zinc-400" />}
 </button>
 {isOpen && (
 <div className="px-5 pb-4 space-y-3 border-t border-zinc-100 pt-3">
 {section.items.map((item, i) => (
 <div key={i} className="pl-11">
 <p className="text-[13px] font-semibold text-zinc-700 mb-1">{item.q}</p>
 <p className="text-[12px] text-zinc-500 leading-relaxed whitespace-pre-line">{item.a}</p>
 </div>
 ))}
 {section.path && (
 <div className="pl-11 pt-2">
 <button type="button"
 onClick={(e) => { e.stopPropagation(); setNavTarget(section.path!); setTimeout(() => navigate(section.path!), 800) }}
 className="flex items-center gap-2 px-4 py-2 rounded-lg text-[12px] font-bold transition-all hover:shadow-md"
 style={{ background: tab === 'platform' ? '#ecfeff' : '#f5f3ff', color: tab === 'platform' ? '#0891b2' : '#7c3aed', border: `1px solid ${tab === 'platform' ? '#a5f3fc' : '#ddd6fe'}` }}>
 <ArrowRight size={14} className={navTarget === section.path ? 'animate-bounce-right' : ''} />
 {lang === 'tr' ? 'Bu sayfaya git' : 'Go to this page'}
 </button>
 </div>
 )}
 </div>
 )}
 </div>
 )
 })}
 </div>
 </div>
 )
}
